<p>{{-- resources/views/home.blade.php --}}</p><p>&lt;!DOCTYPE html&gt;</p><p>&lt;html lang="en" data-lang="en"&gt;</p><p>&lt;head&gt;</p><p>&lt;meta charset="utf-8"/&gt;</p><p>&lt;meta name="viewport" content="width=device-width, initial-scale=1"/&gt;</p><p>&lt;meta name="csrf-token" content="{{ csrf_token() }}"&gt;</p><p>@php</p><p>$siteName = config('<a target="_blank" rel="noopener noreferrer nofollow" href="http://app.name">app.name</a>', 'Semantic SEO Master');</p><p>$metaTitle = $metaTitle ?? 'Semantic SEO Master • Ultra Tech Global';</p><p>$metaDescription = $metaDescription ?? 'Analyze any URL for content quality, entities, technical SEO, and UX signals, with water-fill scoring, auto-checklist, and AI/Human signals.';</p><p>$metaImage = $metaImage ?? asset('og-image.png');</p><p>$canonical = $canonical ?? url()-&gt;current();</p><p>$twitterHandle = '@UltraTechGlobal'; // change to your handle</p><p>@endphp</p><p>&lt;title&gt;{{ $metaTitle }}&lt;/title&gt;</p><p>{{-- Core SEO --}}</p><p>&lt;link rel="canonical" href="{{ $canonical }}"&gt;</p><p>&lt;meta name="description" content="{{ $metaDescription }}"&gt;</p><p>&lt;meta name="robots" content="index,follow,max-image-preview:large,max-snippet:-1,max-video-preview:-1"&gt;</p><p>&lt;link rel="alternate" hreflang="en" href="{{ $canonical }}"/&gt;</p><p>&lt;meta name="keywords" content="SEO analyzer, semantic SEO, content score, technical SEO, entities, E-E-A-T, schema, Core Web Vitals"&gt;</p><p>&lt;meta name="author" content="Ultra Tech Global"&gt;</p><p>&lt;meta name="publisher" content="Ultra Tech Global"&gt;</p><p>&lt;meta name="theme-color" content="#0f1022"&gt;</p><p>&lt;meta name="application-name" content="{{ $siteName }}"&gt;</p><p>{{-- PWA / Platform --}}</p><p>&lt;link rel="manifest" href="{{ asset('site.webmanifest') }}"&gt;</p><p>&lt;link rel="apple-touch-icon" sizes="180x180" href="{{ asset('apple-touch-icon.png') }}"&gt;</p><p>&lt;meta name="apple-mobile-web-app-capable" content="yes"&gt;</p><p>&lt;meta name="apple-mobile-web-app-status-bar-style" content="black-translucent"&gt;</p><p>&lt;meta name="msapplication-TileColor" content="#0f1022"&gt;</p><p>{{-- Open Graph --}}</p><p>&lt;meta property="og:locale" content="en_US"&gt;</p><p>&lt;meta property="og:title" content="{{ $metaTitle }}"&gt;</p><p>&lt;meta property="og:description" content="{{ $metaDescription }}"&gt;</p><p>&lt;meta property="og:type" content="website"&gt;</p><p>&lt;meta property="og:url" content="{{ request()-&gt;fullUrl() }}"&gt;</p><p>&lt;meta property="og:image" content="{{ $metaImage }}"&gt;</p><p>&lt;meta property="og:image:width" content="1200"&gt;</p><p>&lt;meta property="og:image:height" content="630"&gt;</p><p>&lt;meta property="og:site_name" content="{{ $siteName }}"&gt;</p><p>{{-- Twitter Card --}}</p><p>&lt;meta name="twitter:card" content="summary_large_image"&gt;</p><p>&lt;meta name="twitter:site" content="{{ $twitterHandle }}"&gt;</p><p>&lt;meta name="twitter:creator" content="{{ $twitterHandle }}"&gt;</p><p>&lt;meta name="twitter:title" content="{{ $metaTitle }}"&gt;</p><p>&lt;meta name="twitter:description" content="{{ $metaDescription }}"&gt;</p><p>&lt;meta name="twitter:image" content="{{ $metaImage }}"&gt;</p><p>{{-- Structured Data: WebSite, WebPage, Breadcrumb --}}</p><p>&lt;script type="application/ld+json"&gt;</p><p>{</p><p>"@context": "<a target="_blank" rel="noopener noreferrer nofollow" href="https://schema.org">https://schema.org</a>",</p><p>"@type": "WebSite",</p><p>"name": "{{ $siteName }}",</p><p>"url": "{{ url('/') }}",</p><p>"publisher": {</p><p>"@type": "Organization",</p><p>"name": "Ultra Tech Global",</p><p>"logo": { "@type": "ImageObject", "url": "{{ asset('logo.png') }}" }</p><p>},</p><p>"potentialAction": {</p><p>"@type": "SearchAction",</p><p>"target": "{{ url('/') }}?q={search_term_string}",</p><p>"query-input": "required name=search_term_string"</p><p>}</p><p>}</p><p>&lt;/script&gt;</p><p>&lt;script type="application/ld+json"&gt;</p><p>{</p><p>"@context":"<a target="_blank" rel="noopener noreferrer nofollow" href="https://schema.org">https://schema.org</a>",</p><p>"@type":"WebPage",</p><p>"name":"{{ $metaTitle }}",</p><p>"description":"{{ $metaDescription }}",</p><p>"url":"{{ $canonical }}",</p><p>"isPartOf":{"@type":"WebSite","name":"{{ $siteName }}","url":"{{ url('/') }}"},</p><p>"inLanguage":"en-US"</p><p>}</p><p>&lt;/script&gt;</p><p>&lt;script type="application/ld+json"&gt;</p><p>{</p><p>"@context":"<a target="_blank" rel="noopener noreferrer nofollow" href="https://schema.org">https://schema.org</a>",</p><p>"@type":"BreadcrumbList",</p><p>"itemListElement":[</p><p>{"@type":"ListItem","position":1,"name":"Home","item":"{{ url('/') }}"},</p><p>{"@type":"ListItem","position":2,"name":"Analyzer","item":"{{ $canonical }}"}</p><p>]</p><p>}</p><p>&lt;/script&gt;</p><p>&lt;link rel="icon" type="image/x-icon" href="{{ asset('favicon.ico') }}"&gt;</p><p>&lt;link rel="icon" type="image/png" sizes="32x32" href="{{ asset('favicon-32.png') }}"&gt;</p><p>&lt;link rel="icon" type="image/png" sizes="16x16" href="{{ asset('favicon-16.png') }}"&gt;</p><p>&lt;link href="<a target="_blank" rel="noopener noreferrer nofollow" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.0/css/all.min.css">https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.0/css/all.min.css</a>" rel="stylesheet"/&gt;</p><p>&lt;style&gt;</p><p>:root{</p><p>--bg:#07080e; --panel:#0f1022; --panel-2:#141433; --line:#1e1a33;</p><p>--text:#f0effa; --text-dim:#b6b3d6; --text-muted:#9aa0c3;</p><p>--primary:#9b5cff; --secondary:#ff2045; --accent:#3de2ff;</p><p>--good:#22c55e; --warn:#f59e0b; --bad:#ef4444;</p><p>--radius:18px; --shadow:0 10px 40px rgba(0,0,0,.55);</p><p>--container:1200px;</p><p>--hue: 0deg;</p><p>}</p><p>*{box-sizing:border-box} html,body{height:100%}</p><p>html{scroll-behavior:smooth}</p><p>body{</p><p>margin:0; color:var(--text);</p><p>font-family:Inter, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto;</p><p>background: radial-gradient(1200px 700px at 0% -10%, #201046 0%, transparent 55%),</p><p>radial-gradient(1100px 800px at 110% 0%, #1a0f2a 0%, transparent 50%),</p><p>var(--bg);</p><p>overflow-x:hidden;</p><p>}</p><p>/* Decor canvases */</p><p>#linesCanvas, #linesCanvas2, #brainCanvas, #smokeFX { position:fixed; inset:0; z-index:0; pointer-events:none; }</p><p>#brainCanvas{opacity:.10}</p><p>/* Layout */</p><p>.wrap{position:relative;z-index:2;max-width:var(--container);margin:0 auto;padding:28px 5%}</p><p>/* ===== Simple header (restored) ===== */</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://header.site">header.site</a>{</p><p>display:flex; align-items:center; justify-content:space-between;</p><p>gap:1rem; padding:14px 0 22px; border-bottom:1px solid rgba(255,255,255,.08);</p><p>}</p><p>.brand{ display:flex; align-items:center; gap:.8rem; min-width:0 }</p><p>.brand-badge{</p><p>width:48px; height:48px; border-radius:12px; display:grid; place-items:center;</p><p>background:linear-gradient(135deg, rgba(157,92,255,.25), rgba(61,226,255,.25));</p><p>border:1px solid rgba(255,255,255,.14); color:#fff; font-size:1.05rem;</p><p>box-shadow:0 8px 22px rgba(0,0,0,.28);</p><p>}</p><p>.brand-info{ display:flex; flex-direction:column; min-width:0 }</p><p>.hero-heading{ font-weight:1000; letter-spacing:.4px; font-size:clamp(1.4rem,3.2vw,2rem) }</p><p>.hero-sub{ color:var(--text-dim); font-size:.95rem }</p><p>.header-actions{ display:flex; gap:.5rem; align-items:center }</p><p>@media (max-width:768px){ <a target="_blank" rel="noopener noreferrer nofollow" href="http://header.site">header.site</a>{ flex-direction:column; align-items:flex-start; gap:.6rem } }</p><p>/* ======= Buttons (minimal) ======= */</p><p>.btn{</p><p>display:inline-flex; align-items:center; gap:.5rem; cursor:pointer;</p><p>padding:.55rem .9rem; border-radius:12px; border:1px solid rgba(255,255,255,.16);</p><p>color:#fff; background:rgba(255,255,255,.06); font-weight:800; letter-spacing:.2px;</p><p>}</p><p>.btn i{opacity:.95}</p><p>.btn:hover{ background:rgba(255,255,255,.12) }</p><p>.btn:disabled{ opacity:.6; cursor:not-allowed }</p><p>.btn-ghost{ background:transparent }</p><p>.btn-neon{ background:linear-gradient(135deg, #3de2ff33, #9b5cff33) }</p><p>.btn-danger{ background:linear-gradient(135deg, #ff204533, #ff8a5b33) }</p><p>/* Section titles &amp; analyzer */</p><p>.analyzer{margin-top:24px;background:var(--panel);border:1px solid rgba(255,255,255,.08);border-radius:22px;box-shadow:var(--shadow);padding:24px}</p><p>.section-title{font-size:1.6rem;margin:0 0 .3rem}</p><p>.section-subtitle{margin:0;color:var(--text-dim)}</p><p>/* ======= SCORE GAUGE ======= */</p><p>.score-area{display:flex;gap:1.2rem;align-items:center;margin:.6rem 0 0;flex-wrap:wrap}</p><p>.score-container{width:220px}</p><p>.score-gauge{position:relative;width:100%;aspect-ratio:1/1}</p><p>.gauge-svg{width:100%;height:auto;display:block}</p><p>.score-mask-rect{transition:all .6s cubic-bezier(.22,1,.36,1)}</p><p>.score-wave1{animation:scoreWave 8s linear infinite}</p><p>.score-wave2{animation:scoreWave 11s linear infinite reverse}</p><p>@keyframes scoreWave{from{transform:translateX(0)}to{transform:translateX(-210px)}}</p><p>.score-text{font-size:clamp(2.2rem, 4.2vw, 3.1rem);font-weight:1000;fill:#fff;text-shadow:0 0 18px rgba(255,32,69,.25)}</p><p>.multiHueFast{ filter:hue-rotate(var(--hue)) saturate(140%); will-change:filter; }</p><p>/* Chips */</p><p>.chip{padding:.25rem .6rem;border-radius:999px;font-weight:800;background:rgba(155,92,255,.14);border:1px solid rgba(155,92,255,.28);display:inline-flex;align-items:center;gap:.5rem}</p><p>.legend{padding:.25rem .6rem;border-radius:999px;border:1px solid rgba(255,255,255,.16);font-weight:800}</p><p>.l-red{background:rgba(239,68,68,.18)} .l-orange{background:rgba(245,158,11,.18)} .l-green{background:rgba(34,197,94,.18)}</p><p>.chip-good{background:rgba(34,197,94,.18)!important;border-color:rgba(34,197,94,.45)!important}</p><p>.chip-mid{background:rgba(245,158,11,.18)!important;border-color:rgba(245,158,11,.45)!important}</p><p>.chip-bad{background:rgba(239,68,68,.18)!important;border-color:rgba(239,68,68,.5)!important}</p><p>.ico{width:1.1em;text-align:center}</p><p>.ico-green{color:var(--good)} .ico-orange{color:var(--warn)} .ico-red{color:var(--bad)} .ico-cyan{color:var(--accent)} .ico-purple{color:#9b5cff}</p><p>/* URL field */</p><p>.analyze-form input[type="url"]{</p><p>width:100%; padding:1rem 1.2rem; border-radius:16px;</p><p>border:1px solid #1b1b35; background:#0b0d21; color:var(--text); transition:.25s;</p><p>}</p><p>.analyze-form input[type="url"]:focus{ outline:none; border-color:#5942ff; box-shadow:0 0 0 6px rgba(155,92,255,.15); }</p><p>.url-label{display:inline-block;font-weight:900;margin-bottom:.35rem;position:relative}</p><p>.url-label.animating{</p><p>background:linear-gradient(90deg,#fff,#9b5cff,#3de2ff,#fff);</p><p>-webkit-background-clip:text; -webkit-text-fill-color:transparent;</p><p>animation:shine 1.2s linear infinite;</p><p>}</p><p>.url-label.animating::after{</p><p>content:""; position:absolute; left:0; right:0; bottom:-4px; height:3px;</p><p>background:linear-gradient(90deg,#3de2ff,#9b5cff,#ff2045,#3de2ff);</p><p>filter:blur(.3px); border-radius:999px; animation:underlineWave 1.6s ease-in-out infinite;</p><p>}</p><p>@keyframes shine{0%{background-position:0%}100%{background-position:200%}}</p><p>@keyframes underlineWave{0%,100%{transform:translateX(0)}50%{transform:translateX(8px)}}</p><p>.analyze-row{display:grid;grid-template-columns:1fr auto auto auto auto;gap:.6rem;align-items:center;margin-top:.5rem}</p><p>/* ======= Analyze water progress ======= */</p><p>.water-wrap{margin-top:.8rem;display:none}</p><p>.waterbar{position:relative; height:64px; border-radius:18px; overflow:hidden;background:#0b0d21; border:1px solid rgba(255,255,255,.1)}</p><p>.water-svg{position:absolute; inset:0; width:100%; height:100%; z-index:1;}</p><p>.water-mask-rect{transition:all .25s ease-out}</p><p>.water-overlay{position:absolute; inset:0; pointer-events:none; background:</p><p>radial-gradient(120px 60px at 20% -20%, rgba(255,255,255,.18), transparent 60%),</p><p>linear-gradient(0deg, rgba(255,255,255,.05), transparent 40%, transparent 60%, rgba(255,255,255,.06));</p><p>mix-blend-mode:screen; z-index:2}</p><p>.water-pct{position:absolute; inset:0; display:grid; place-items:center; font-weight:1000; font-size:1.05rem; text-shadow:0 1px 0 rgba(0,0,0,.45); letter-spacing:.4px; z-index:4}</p><p>.wave1{animation:waveX 7s linear infinite}</p><p>.wave2{animation:waveX 10s linear infinite reverse; opacity:.7}</p><p>@keyframes waveX{0%{transform:translateX(0)}100%{transform:translateX(-600px)}}</p><p>.multiHue{filter:hue-rotate(var(--hue)) saturate(140%); will-change:filter;}</p><p>#waterSmoke{ position:absolute; inset:0; pointer-events:none; z-index:3; mix-blend-mode:screen; }</p><p>/* ======= COMPLETION (Items Completed) – Water + Smoke ======= */</p><p>.progress-wrap{margin-top:1rem;background:rgba(255,255,255,.02);border:1px solid rgba(255,255,255,.06);border-radius:16px;padding:14px}</p><p>.comp-water{position:relative; height:52px; border-radius:16px; overflow:hidden; background:#0b0d21; border:1px solid rgba(255,255,255,.1); }</p><p>.comp-svg{position:absolute; inset:0; width:100%; height:100%; z-index:1;}</p><p>.comp-overlay{position:absolute; inset:0; background:</p><p>radial-gradient(120px 50px at 15% -25%, rgba(255,255,255,.16), transparent 55%),</p><p>linear-gradient(180deg, rgba(255,255,255,.08), transparent 35%, rgba(255,255,255,.06));</p><p>pointer-events:none; mix-blend-mode:screen; z-index:3;}</p><p>.comp-pct{position:absolute; inset:0; display:grid; place-items:center; font-weight:1000; font-size:1rem; z-index:4; text-shadow:0 1px 0 rgba(0,0,0,.45); }</p><p>#compSmoke{ position:absolute; inset:0; pointer-events:none; z-index:2; mix-blend-mode:screen; }</p><p>.comp-wave1{animation:waveX 8s linear infinite}</p><p>.comp-wave2{animation:waveX 12s linear infinite reverse}</p><p>.progress-caption{color:var(--text-muted);font-size:.95rem;margin-top:.55rem}</p><p>/* Category grid */</p><p>.analyzer-grid{margin-top:1.1rem;display:grid;grid-template-columns:repeat(12,1fr);gap:1rem}</p><p>.category-card{position:relative;grid-column:span 6;background:var(--panel-2);border:1px solid rgba(255,255,255,.08);border-radius:16px;padding:16px;box-shadow:var(--shadow);overflow:hidden; isolation:isolate;}</p><p>.category-card::before{content:"";position:absolute;inset:-2px;border-radius:18px;padding:2px;background:linear-gradient(120deg,rgba(61,226,255,.4),rgba(155,92,255,.4),rgba(255,32,69,.4));-webkit-mask:linear-gradient(#000 0 0) content-box,linear-gradient(#000 0 0);-webkit-mask-composite:xor;mask-composite:exclude;animation:borderGlow 6s linear infinite; pointer-events:none; z-index:0;}</p><p>.category-card &gt; *{position:relative; z-index:1;}</p><p>@keyframes borderGlow{0%{filter:hue-rotate(0)}100%{filter:hue-rotate(360deg)}}</p><p>/* Heading row */</p><p>.category-head{display:grid;grid-template-columns:auto 1fr auto;gap:.75rem;align-items:center}</p><p>.category-icon{width:48px;height:48px;border-radius:14px;display:inline-flex;align-items:center;justify-content:center;background:linear-gradient(135deg,#3de2ff33,#9b5cff33);color:#fff;font-size:1.1rem;border:1px solid rgba(255,255,255,.18)}</p><p>.category-title{margin:0;font-size:1.08rem;background:linear-gradient(90deg,#3de2ff,#9b5cff,#ff2045);-webkit-background-clip:text;-webkit-text-fill-color:transparent;font-weight:900}</p><p>.category-sub{margin:.15rem 0 0;color:var(--text-dim);font-size:.96rem}</p><p>/* Water-fill heading bar + smoke */</p><p>.cat-water{grid-column:1/-1; margin-top:.55rem; position:relative; height:22px;}</p><p>.cat-svg{display:block; width:100%; height:22px;}</p><p>.cat-wave1{animation:catWave 7s linear infinite}</p><p>.cat-wave2{animation:catWave 10s linear infinite reverse}</p><p>@keyframes catWave{from{transform:translateX(0)}to{transform:translateX(-640px)}}</p><p>.cat-water-pct{position:absolute; inset:0; display:flex; align-items:center; justify-content:center; font-weight:900; font-size:.8rem; color:rgba(255,255,255,.9); text-shadow:0 1px 0 rgba(0,0,0,.55); pointer-events:none}</p><p>.cat-smoke{position:absolute; left:0; right:0; bottom:0; height:26px; pointer-events:none; z-index:3; mix-blend-mode:screen;}</p><p>/* Items (improved box colors) */</p><p>.checklist{list-style:none;margin:10px 0 0;padding:0}</p><p>.checklist-item{</p><p>display:grid;grid-template-columns:1fr auto auto auto;gap:.6rem;align-items:center;</p><p>padding:.7rem .75rem;border-radius:14px;</p><p>border:1px solid rgba(255,255,255,.10);</p><p>background:</p><p>linear-gradient(180deg, rgba(255,255,255,.04), rgba(255,255,255,.02)),</p><p>radial-gradient(100% 120% at 0% 0%, rgba(61,226,255,.06), transparent 30%),</p><p>radial-gradient(120% 100% at 100% 0%, rgba(155,92,255,.05), transparent 35%);</p><p>transition: box-shadow .25s ease, background .25s ease, transform .12s ease;</p><p>}</p><p>.checklist-item + .checklist-item{margin-top:.28rem}</p><p>.checklist-item:hover{transform:translateY(-2px);box-shadow:0 8px 30px rgba(0,0,0,.25)}</p><p>.checklist-item label { cursor:pointer; display:inline-flex; align-items:center; gap:.55rem; }</p><p>/* Severity glow + tints */</p><p>.sev-good{</p><p>background:</p><p>linear-gradient(180deg, rgba(34,197,94,.14), rgba(34,197,94,.08)),</p><p>radial-gradient(100% 120% at 0% 0%, rgba(61,226,255,.06), transparent 30%);</p><p>border-color: rgba(34,197,94,.45);</p><p>}</p><p>.sev-mid{</p><p>background:</p><p>linear-gradient(180deg, rgba(245,158,11,.16), rgba(245,158,11,.08)),</p><p>radial-gradient(100% 120% at 0% 0%, rgba(61,226,255,.06), transparent 30%);</p><p>border-color: rgba(245,158,11,.45);</p><p>}</p><p>.sev-bad{</p><p>background:</p><p>linear-gradient(180deg, rgba(239,68,68,.16), rgba(239,68,68,.10)),</p><p>radial-gradient(100% 120% at 0% 0%, rgba(61,226,255,.06), transparent 30%);</p><p>border-color: rgba(239,68,68,.55);</p><p>}</p><p>.sev-mid .improve-btn, .sev-bad .improve-btn{animation:attentionPulse 1.6s ease-in-out infinite}</p><p>@keyframes attentionPulse{</p><p>0%,100%{ box-shadow:0 0 0 0 rgba(255,255,255,.0), 0 0 0 0 rgba(255,255,255,.0)}</p><p>50%{ box-shadow:0 0 0 6px rgba(255,255,255,.06), 0 0 12px 0 rgba(255,255,255,.08)}</p><p>}</p><p>/* Row flash */</p><p>.flash-row{animation:rowFlash 900ms ease-out}</p><p>@keyframes rowFlash{</p><p>0%{ background:linear-gradient(90deg,rgba(61,226,255,.20),rgba(155,92,255,.16)); }</p><p>100%{ background:</p><p>linear-gradient(180deg, rgba(255,255,255,.04), rgba(255,255,255,.02)),</p><p>radial-gradient(100% 120% at 0% 0%, rgba(61,226,255,.06), transparent 30%),</p><p>radial-gradient(120% 100% at 100% 0%, rgba(155,92,255,.05), transparent 35%); }</p><p>}</p><p>/* Custom checkbox */</p><p>.checklist-item input[type="checkbox"]{</p><p>appearance:none; -webkit-appearance:none; outline:none;</p><p>width:22px;height:22px;border-radius:8px;</p><p>background:#0b1220; border:2px solid #2a2f4d;</p><p>position:relative; display:inline-grid; place-items:center;</p><p>transition:.18s ease-in-out; box-shadow:inset 0 0 0 0 rgba(99,102,241,.0);</p><p>}</p><p>.checklist-item input[type="checkbox"]:hover{</p><p>border-color:#4c5399; box-shadow:0 0 0 4px rgba(99,102,241,.12);</p><p>}</p><p>.checklist-item input[type="checkbox"]:checked{</p><p>border-color:transparent;</p><p>background:linear-gradient(135deg,#22c55e,#3de2ff,#9b5cff);</p><p>background-size:200% 200%; animation:tickHue 2s linear infinite;</p><p>box-shadow:0 6px 18px rgba(61,226,255,.25), inset 0 0 0 2px rgba(255,255,255,.25);</p><p>}</p><p>@keyframes tickHue{0%{background-position:0% 50%}100%{background-position:200% 50%}}</p><p>.checklist-item input[type="checkbox"]::after{</p><p>content:""; width:7px;height:12px; border:3px solid transparent;</p><p>border-left:0;border-top:0; transform:rotate(45deg) scale(.7);</p><p>transition:.18s ease-in-out;</p><p>}</p><p>.checklist-item input[type="checkbox"]:checked::after{</p><p>border-color:#fff; filter:drop-shadow(0 1px 0 rgba(0,0,0,.4));</p><p>transform:rotate(45deg) scale(1);</p><p>}</p><p>/* Score badges + Improve button */</p><p>.score-badge{font-weight:900;font-size:.95rem;padding:.3rem .65rem;border-radius:999px;border:1px solid rgba(255,255,255,.12);background:rgba(255,255,255,.06);min-width:52px;text-align:center}</p><p>.score-good{background:rgba(22,193,114,.22); border-color:rgba(22,193,114,.45)}</p><p>.score-mid{ background:rgba(245,158,11,.22); border-color:rgba(245,158,11,.45)}</p><p>.score-bad{ background:rgba(239,68,68,.24); border-color:rgba(239,68,68,.5)}</p><p>.improve-btn{</p><p>position:relative; overflow:hidden;</p><p>padding:.45rem .8rem;border-radius:999px;border:1px solid rgba(255,255,255,.14);</p><p>background:linear-gradient(135deg,rgba(255,255,255,.06),rgba(255,255,255,.02));</p><p>font-weight:900; cursor:pointer; transition:.2s;</p><p>isolation:isolate; min-width:88px;</p><p>}</p><p>.improve-btn:hover{ transform:translateY(-1px); background:rgba(255,255,255,.1); }</p><p>.improve-btn:active{ transform:translateY(0); }</p><p>.improve-btn::before{</p><p>content:""; position:absolute; inset:-2px; border-radius:inherit; z-index:0;</p><p>background:linear-gradient(120deg, transparent 0%, rgba(255,255,255,.18) 45%, transparent 50%, transparent 100%);</p><p>transform:translateX(-120%); animation:btnSheen 3.2s linear infinite;</p><p>}</p><p>@keyframes btnSheen{ 0%{transform:translateX(-120%)} 60%{transform:translateX(120%)} 100%{transform:translateX(120%)} }</p><p>.improve-btn .ripple{</p><p>position:absolute; border-radius:50%; pointer-events:none; z-index:1;</p><p>transform:translate(-50%,-50%); background:radial-gradient(circle, rgba(255,255,255,.35) 0%, rgba(255,255,255,.15) 40%, rgba(255,255,255,0) 70%);</p><p>width:10px; height:10px; animation:ripple .65s ease-out forwards;</p><p>}</p><p>@keyframes ripple{ to{ width:220px; height:220px; opacity:0 } }</p><p>.fx-burst{ position:fixed; left:0; top:0; width:0; height:0; pointer-events:none; z-index:120 }</p><p>.fx-spark{</p><p>position:absolute; width:8px;height:8px;border-radius:50%;</p><p>background: radial-gradient(circle at 30% 30%, #fff, rgba(255,255,255,.2) 40%, rgba(255,255,255,0) 70%);</p><p>box-shadow:0 0 12px rgba(255,255,255,.45);</p><p>animation:spark .8s ease-out forwards;</p><p>}</p><p>@keyframes spark{</p><p>to{ transform:translate(var(--dx), var(--dy)) rotate(220deg) scale(.6); opacity:0; }</p><p>}</p><p>/* Floating Share Dock (colorful + effect) */</p><p>.share-dock{</p><p>position:fixed; right:16px; top:50%; transform:translateY(-50%);</p><p>display:flex; flex-direction:column; gap:.5rem; z-index:85;</p><p>background:rgba(10,12,28,.35); border:1px solid rgba(255,255,255,.12); border-radius:14px; padding:.5rem;</p><p>backdrop-filter:blur(8px);</p><p>}</p><p>.share-btn{</p><p>width:42px;height:42px;border-radius:12px;border:1px solid rgba(255,255,255,.16);</p><p>display:grid;place-items:center;color:#fff;background:rgba(255,255,255,.06); cursor:pointer; text-decoration:none;</p><p>position:relative; overflow:hidden; transition:transform .15s ease, box-shadow .15s ease;</p><p>}</p><p>.share-btn:hover{ transform:translateY(-2px); box-shadow:0 10px 24px rgba(0,0,0,.35) }</p><p>.share-btn::after{</p><p>content:""; position:absolute; inset:-2px; background:radial-gradient(120px 40px at -20% -20%, rgba(255,255,255,.3), transparent 55%); mix-blend-mode:screen; opacity:.6;</p><p>}</p><p>.share-btn i{ font-size:1.05rem }</p><p>.share-native{ display:none; }</p><p>.share-fb{ background:linear-gradient(135deg,#1877F2,#3b5998); }</p><p>.share-x { background:linear-gradient(135deg,#000000,#232323); }</p><p>.share-ln{ background:linear-gradient(135deg,#0a66c2,#1d87e5); }</p><p>.share-wa{ background:linear-gradient(135deg,#25D366,#128C7E); }</p><p>.share-em{ background:linear-gradient(135deg,#ff7a59,#ff2045); }</p><p>/* Footer + back to top */</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://footer.site">footer.site</a>{ margin-top:28px;padding:18px 5%;background:rgba(255,255,255,.04);border-top:1px solid rgba(255,255,255,.12);display:flex;align-items:center;justify-content:space-between;gap:1rem;backdrop-filter:blur(6px)}</p><p>.footer-brand{display:flex;align-items:center;gap:.6rem}</p><p>.footer-brand .dot{width:8px;height:8px;border-radius:50%;background:linear-gradient(135deg,#3de2ff,#9b5cff)}</p><p>.footer-links a{color:var(--text-dim);margin-left:.9rem}</p><p>.footer-links a:hover{color:#fff;text-decoration:underline}</p><p>#backTop{position:fixed;right:18px;bottom:18px;z-index:90;width:48px;height:48px;border-radius:14px;border:1px solid rgba(255,255,255,.16);background:rgba(255,255,255,.07);display:grid;place-items:center;color:#fff;cursor:pointer;display:none}</p><p>#backTop:hover{background:rgba(255,255,255,.12)}</p><p>/* ======= Mobile Optimizations ======= */</p><p>@media (max-width:1200px){ .wrap{padding:24px 4%} }</p><p>@media (max-width:992px){</p><p>.category-card{grid-column:span 12}</p><p>.score-container{width:190px}</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://footer.site">footer.site</a>{flex-direction:column;align-items:flex-start}</p><p>.analyze-row{ grid-template-columns:1fr auto auto; grid-row-gap:.5rem; }</p><p>}</p><p>@media (max-width:768px){</p><p>.wrap{padding:18px 4%}</p><p>.score-area{flex-direction:column;align-items:flex-start;gap:.8rem}</p><p>.score-container{width:170px}</p><p>.analyze-row{ grid-template-columns:1fr; }</p><p>.analyze-row .btn{ width:100%; justify-content:center; }</p><p>.share-dock{</p><p>top:auto; bottom:10px; right:50%; transform:translateX(50%);</p><p>flex-direction:row; padding:.35rem .45rem; border-radius:999px;</p><p>gap:.4rem; background:rgba(10,12,28,.55);</p><p>}</p><p>.share-btn{ width:44px;height:44px;border-radius:999px }</p><p>.share-native{ display:grid; }</p><p>.checklist-item{ grid-template-columns:1fr auto auto; }</p><p>.checklist-item .improve-btn{ grid-column: 1 / -1; justify-self:flex-start; margin-top:.25rem; }</p><p>}</p><p>@media (max-width:480px){</p><p>.score-container{width:150px}</p><p>.category-icon{width:40px;height:40px}</p><p>.category-title{font-size:1rem}</p><p>}</p><p>/* Reduced motion */</p><p>@media (prefers-reduced-motion: reduce){</p><p>.score-wave1,.score-wave2,.wave1,.wave2,.cat-wave1,.cat-wave2,.comp-wave1,.comp-wave2{ animation:none !important }</p><p>.multiHue,.multiHueFast{ filter:none !important }</p><p>}</p><p>@media print{#linesCanvas,#linesCanvas2,#brainCanvas,#smokeFX,.modal-backdrop,.modal,<a target="_blank" rel="noopener noreferrer nofollow" href="http://header.site">header.site</a> #backTop,.lang-dock,.lang-panel,.share-dock{display:none!important}}</p><p>/* Modal */</p><p>.modal-backdrop{position:fixed;inset:0;background:rgba(0,0,0,.5);display:none;z-index:95}</p><p>.modal{position:fixed;inset:0;display:none;align-items:center;justify-content:center;z-index:100}</p><p>.modal-card{width:min(980px,95vw);max-height:85vh;overflow:auto;background:var(--panel-2);border:1px solid rgba(255,255,255,.14);border-radius:18px;box-shadow:var(--shadow);padding:16px}</p><p>.modal-header{display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid rgba(255,255,255,.12);padding-bottom:8px;margin-bottom:8px}</p><p>.modal-title{margin:0;font-weight:900}</p><p>.modal-close{background:transparent;border:1px solid rgba(255,255,255,.18);border-radius:10px;color:#fff;padding:.35rem .6rem;cursor:pointer}</p><p>.tabs{display:flex;gap:.5rem;border-bottom:1px solid rgba(255,255,255,.12);padding-bottom:.3rem;margin-bottom:.5rem}</p><p>.tab{padding:.4rem .7rem;border:1px solid rgba(255,255,255,.14);border-bottom:none;border-radius:12px 12px 0 0;background:rgba(255,255,255,.05);cursor:pointer;font-weight:900}</p><p>.tab.active{background:linear-gradient(135deg,#3de2ff33,#9b5cff33)}</p><p>.tabpanes &gt; div{display:none;padding:.6rem .2rem}</p><p>.tabpanes &gt; div.active{display:block}</p><p>.pre{white-space:pre-wrap;background:#0b0d21;border:1px solid rgba(255,255,255,.08);border-radius:12px;padding:10px}</p><p>&lt;/style&gt;</p><p>&lt;/head&gt;</p><p>&lt;body&gt;</p><p>&lt;canvas id="brainCanvas" aria-hidden="true"&gt;&lt;/canvas&gt;</p><p>&lt;canvas id="linesCanvas" aria-hidden="true"&gt;&lt;/canvas&gt;</p><p>&lt;canvas id="linesCanvas2" aria-hidden="true"&gt;&lt;/canvas&gt;</p><p>&lt;canvas id="smokeFX" aria-hidden="true"&gt;&lt;/canvas&gt;</p><p>&lt;!-- Gradients for main + completion water --&gt;</p><p>&lt;svg width="0" height="0" aria-hidden="true"&gt;</p><p>&lt;defs&gt;</p><p>&lt;linearGradient id="grad" x1="0%" y1="0%" x2="100%"&gt;&lt;stop offset="0%" stop-color="#9b5cff"/&gt;&lt;stop offset="100%" stop-color="#ff2045"/&gt;&lt;/linearGradient&gt;</p><p>&lt;linearGradient id="gradGood" x1="0%" y1="0%" x2="100%"&gt;&lt;stop offset="0%" stop-color="#22c55e"/&gt;&lt;stop offset="100%" stop-color="#16a34a"/&gt;&lt;/linearGradient&gt;</p><p>&lt;linearGradient id="gradMid" x1="0%" y1="0%" x2="100%"&gt;&lt;stop offset="0%" stop-color="#f59e0b"/&gt;&lt;stop offset="100%" stop-color="#fb923c"/&gt;&lt;/linearGradient&gt;</p><p>&lt;linearGradient id="gradBad" x1="0%" y1="0%" x2="100%"&gt;&lt;stop offset="0%" stop-color="#ef4444"/&gt;&lt;stop offset="100%" stop-color="#b91c1c"/&gt;&lt;/linearGradient&gt;</p><p>&lt;/defs&gt;</p><p>&lt;/svg&gt;</p><p>&lt;!-- Language Dock --&gt;</p><p>&lt;div class="lang-dock" style="position:fixed;left:18px;top:50%;transform:translateY(-50%);z-index:70;display:flex;flex-direction:column;gap:.6rem"&gt;</p><p>&lt;button class="btn" id="langOpen" title="Language" style="width:48px;height:48px;border-radius:12px;"&gt;&lt;i class="fa-solid fa-globe"&gt;&lt;/i&gt;&lt;/button&gt;</p><p>&lt;/div&gt;</p><p>&lt;div class="lang-panel" id="langPanel"&gt;&lt;div class="lang-card" id="langCard"&gt;&lt;/div&gt;&lt;/div&gt;</p><p>&lt;!-- Floating Share (colorful) --&gt;</p><p>&lt;div class="share-dock" id="shareDock" aria-label="Share"&gt;</p><p>&lt;a id="shareFb" class="share-btn share-fb" aria-label="Share on Facebook" target="_blank" rel="noopener nofollow"&gt;&lt;i class="fa-brands fa-facebook-f"&gt;&lt;/i&gt;&lt;/a&gt;</p><p>&lt;a id="shareX" class="share-btn share-x" aria-label="Share on X" target="_blank" rel="noopener nofollow"&gt;&lt;i class="fa-brands fa-x-twitter"&gt;&lt;/i&gt;&lt;/a&gt;</p><p>&lt;a id="shareLn" class="share-btn share-ln" aria-label="Share on LinkedIn" target="_blank" rel="noopener nofollow"&gt;&lt;i class="fa-brands fa-linkedin-in"&gt;&lt;/i&gt;&lt;/a&gt;</p><p>&lt;a id="shareWa" class="share-btn share-wa" aria-label="Share on WhatsApp" target="_blank" rel="noopener nofollow"&gt;&lt;i class="fa-brands fa-whatsapp"&gt;&lt;/i&gt;&lt;/a&gt;</p><p>&lt;a id="shareEm" class="share-btn share-em" aria-label="Share via Email" target="_blank" rel="noopener"&gt;&lt;i class="fa-solid fa-envelope"&gt;&lt;/i&gt;&lt;/a&gt;</p><p>&lt;button id="shareNative" class="share-btn share-x share-native" aria-label="Share"&gt;&lt;i class="fa-solid fa-share-nodes"&gt;&lt;/i&gt;&lt;/button&gt;</p><p>&lt;/div&gt;</p><p>&lt;div class="wrap"&gt;</p><p>&lt;!-- ===== Simple Header (restored) ===== --&gt;</p><p>&lt;header class="site"&gt;</p><p>&lt;div class="brand"&gt;</p><p>&lt;div class="brand-badge" aria-hidden="true"&gt;</p><p>&lt;i class="fa-solid fa-brain"&gt;&lt;/i&gt;</p><p>&lt;/div&gt;</p><p>&lt;div class="brand-info"&gt;</p><p>&lt;div class="hero-heading" data-i="title"&gt;Semantic SEO Master Analyzer&lt;/div&gt;</p><p>&lt;div class="hero-sub"&gt;Analyze URLs, get scores &amp; suggestions&lt;/div&gt;</p><p>&lt;/div&gt;</p><p>&lt;/div&gt;</p><p>&lt;div class="header-actions"&gt;</p><p>&lt;button class="btn btn-ghost" id="printTop"&gt;</p><p>&lt;i class="fa-solid fa-print"&gt;&lt;/i&gt; &lt;span data-i="print"&gt;Print&lt;/span&gt;</p><p>&lt;/button&gt;</p><p>&lt;/div&gt;</p><p>&lt;/header&gt;</p><p>&lt;!-- ===== /Header ===== --&gt;</p><p>&lt;main class="analyzer" id="analyzer" role="main" aria-label="Semantic SEO Analyzer"&gt;</p><p>&lt;h2 class="section-title" data-i="analyze_title"&gt;Analyze a URL&lt;/h2&gt;</p><p>&lt;p class="section-subtitle" data-i="legend_line"&gt;</p><p>The wheel fills with your overall score. &lt;span class="legend l-green"&gt;Green ≥ 80&lt;/span&gt; &lt;span class="legend l-orange"&gt;Orange 60–79&lt;/span&gt; &lt;span class="legend l-red"&gt;Red &amp;lt; 60&lt;/span&gt;</p><p>&lt;/p&gt;</p><p>&lt;div class="score-area"&gt;</p><p>&lt;div class="score-container"&gt;</p><p>&lt;!-- Gauge --&gt;</p><p>&lt;div class="score-gauge"&gt;</p><p>&lt;svg class="gauge-svg" viewBox="0 0 200 200" aria-label="Overall score gauge"&gt;</p><p>&lt;defs&gt;</p><p>&lt;clipPath id="scoreCircleClip"&gt;&lt;circle cx="100" cy="100" r="88"/&gt;&lt;/clipPath&gt;</p><p>&lt;clipPath id="scoreFillClip"&gt;&lt;rect id="scoreClipRect" class="score-mask-rect" x="0" y="200" width="200" height="200"/&gt;&lt;/clipPath&gt;</p><p>&lt;linearGradient id="scoreGrad" x1="0" y1="0" x2="1" y2="1"&gt;</p><p>&lt;stop id="scoreStop1" offset="0%" stop-color="#22c55e"/&gt;</p><p>&lt;stop id="scoreStop2" offset="100%" stop-color="#16a34a"/&gt;</p><p>&lt;/linearGradient&gt;</p><p>&lt;linearGradient id="ringGrad" x1="0" y1="0" x2="1" y2="1"&gt;</p><p>&lt;stop id="ringStop1" offset="0%" stop-color="#22c55e"/&gt;</p><p>&lt;stop id="ringStop2" offset="100%" stop-color="#16a34a"/&gt;</p><p>&lt;/linearGradient&gt;</p><p>&lt;filter id="ringGlow" x="-50%" y="-50%" width="200%" height="200%"&gt;</p><p>&lt;feGaussianBlur stdDeviation="2.4" result="b"/&gt;</p><p>&lt;feMerge&gt;&lt;feMergeNode in="b"/&gt;&lt;feMergeNode in="SourceGraphic"/&gt;&lt;/feMerge&gt;</p><p>&lt;/filter&gt;</p><p>&lt;path id="scoreWavePath" d="M0 110 Q 15 90 30 110 T 60 110 T 90 110 T 120 110 T 150 110 T 180 110 T 210 110 V 220 H 0 Z"/&gt;</p><p>&lt;/defs&gt;</p><p>&lt;circle cx="100" cy="100" r="96" fill="rgba(255,255,255,.06)" stroke="rgba(255,255,255,.12)" stroke-width="2"/&gt;</p><p>&lt;circle id="ringTrack" cx="100" cy="100" r="95" fill="none" stroke="rgba(255,255,255,.12)" stroke-width="6" transform="rotate(-90 100 100)"/&gt;</p><p>&lt;circle id="ringArc" cx="100" cy="100" r="95" fill="none" stroke="url(#ringGrad)" stroke-width="6" stroke-linecap="round" filter="url(#ringGlow)" opacity=".95" transform="rotate(-90 100 100)" /&gt;</p><p>&lt;g clip-path="url(#scoreCircleClip)"&gt;</p><p>&lt;rect x="0" y="0" width="200" height="200" fill="#0b0d21"/&gt;</p><p>&lt;g clip-path="url(#scoreFillClip)"&gt;</p><p>&lt;g class="score-wave1 multiHueFast"&gt;</p><p>&lt;use href="#scoreWavePath" x="0" fill="url(#scoreGrad)"/&gt;</p><p>&lt;use href="#scoreWavePath" x="210" fill="url(#scoreGrad)"/&gt;</p><p>&lt;/g&gt;</p><p>&lt;g class="score-wave2 multiHueFast" opacity=".85"&gt;</p><p>&lt;use href="#scoreWavePath" x="0" y="6" fill="url(#scoreGrad)"/&gt;</p><p>&lt;use href="#scoreWavePath" x="210" y="6" fill="url(#scoreGrad)"/&gt;</p><p>&lt;/g&gt;</p><p>&lt;/g&gt;</p><p>&lt;/g&gt;</p><p>&lt;text id="overallScore" x="100" y="106" text-anchor="middle" dominant-baseline="middle" class="score-text"&gt;0%&lt;/text&gt;</p><p>&lt;/svg&gt;</p><p>&lt;/div&gt;</p><p>&lt;/div&gt;</p><p>&lt;div style="display:flex;flex-direction:column;gap:.5rem"&gt;</p><p>&lt;div style="display:flex;gap:.5rem;flex-wrap:wrap"&gt;</p><p>&lt;span class="chip" id="overallChip"&gt;&lt;i class="fa-solid fa-gauge-high ico"&gt;&lt;/i&gt; &lt;span data-i="overall"&gt;Overall&lt;/span&gt;: &lt;b id="overallScoreInline"&gt;0&lt;/b&gt;/100&lt;/span&gt;</p><p>&lt;span class="chip" id="contentScoreChip"&gt;&lt;i class="fa-solid fa-file-lines ico"&gt;&lt;/i&gt; Content: &lt;b id="contentScoreInline"&gt;0&lt;/b&gt;/100&lt;/span&gt;</p><p>&lt;span class="chip" id="aiBadge" title="AI/Human detection summary"&gt;&lt;i class="fa-solid fa-user-check ico ico-green"&gt;&lt;/i&gt; Writer: &lt;b&gt;—&lt;/b&gt;&lt;/span&gt;</p><p>&lt;button id="viewHumanBtn" class="btn btn-