odal="true" aria-labelledby="modalTitle"&gt;</p><p>&lt;div class="modal-card"&gt;</p><p>&lt;div class="modal-header"&gt;</p><p>&lt;h3 class="modal-title" id="modalTitle"&gt;Improve&lt;/h3&gt;</p><p>&lt;button class="modal-close" id="modalClose" aria-label="Close dialog"&gt;&lt;i class="fa-solid fa-xmark"&gt;&lt;/i&gt;&lt;/button&gt;</p><p>&lt;/div&gt;</p><p>&lt;div class="tabs" role="tablist"&gt;</p><p>&lt;button class="tab active" data-tab="tipsTab" role="tab"&gt;&lt;i class="fa-solid fa-lightbulb"&gt;&lt;/i&gt; Tips&lt;/button&gt;</p><p>&lt;button class="tab" data-tab="examplesTab" role="tab"&gt;&lt;i class="fa-brands fa-google"&gt;&lt;/i&gt; Examples (Google)&lt;/button&gt;</p><p>&lt;button class="tab" data-tab="humanTab" role="tab"&gt;&lt;i class="fa-solid fa-user"&gt;&lt;/i&gt; Human-like&lt;/button&gt;</p><p>&lt;button class="tab" data-tab="aiTab" role="tab"&gt;&lt;i class="fa-solid fa-microchip"&gt;&lt;/i&gt; AI-like&lt;/button&gt;</p><p>&lt;button class="tab" data-tab="fullTab" role="tab"&gt;&lt;i class="fa-solid fa-file-lines"&gt;&lt;/i&gt; Full Text&lt;/button&gt;</p><p>&lt;/div&gt;</p><p>&lt;div class="tabpanes"&gt;</p><p>&lt;div id="tipsTab" class="active"&gt;&lt;ul id="modalList"&gt;&lt;/ul&gt;&lt;/div&gt;</p><p>&lt;div id="examplesTab"&gt;&lt;div class="pre" id="examplesPre"&gt;—&lt;/div&gt;&lt;/div&gt;</p><p>&lt;div id="humanTab"&gt;&lt;div class="pre" id="humanSnippetsPre"&gt;Run Analyze to view human-like snippets.&lt;/div&gt;&lt;/div&gt;</p><p>&lt;div id="aiTab"&gt;&lt;div class="pre" id="aiSnippetsPre"&gt;Run Analyze to view AI-like snippets.&lt;/div&gt;&lt;/div&gt;</p><p>&lt;div id="fullTab"&gt;&lt;div class="pre" id="fullTextPre"&gt;Run Analyze to load full text.&lt;/div&gt;&lt;/div&gt;</p><p>&lt;/div&gt;</p><p>&lt;/div&gt;</p><p>&lt;/div&gt;</p><p>&lt;script&gt;</p><p>/* ---------- i18n ---------- */</p><p>const I18N = { en:{title:"Semantic SEO Master Analyzer", analyze_title:"Analyze a URL", legend_line:"The wheel fills with your overall score. &lt;span class='legend l-green'&gt;Green ≥ 80&lt;/span&gt; &lt;span class='legend l-orange'&gt;Orange 60–79&lt;/span&gt; &lt;span class='legend l-red'&gt;Red &amp;lt; 60&lt;/span&gt;", overall:"Overall", page_url:"Page URL", analyze:"Analyze", print:"Print", reset:"Reset", auto_check:"Auto-apply checkmarks (≥ 80)"} };</p><p>const LANGS = [["en","English"]];</p><p>(function(){</p><p>const dockBtn = document.getElementById('langOpen');</p><p>const panel = document.getElementById('langPanel');</p><p>const card = document.getElementById('langCard');</p><p>function fill(){ card.innerHTML=''; LANGS.forEach(([code,label])=&gt;{ const div=document.createElement('div'); div.className='lang-item'; div.dataset.code=code; div.innerHTML<code>&lt;span class="lang-flag" style="background:#888"&gt;&lt;/span&gt;&lt;strong&gt;${label}&lt;/strong&gt;</code>; card.appendChild(div); }); }</p><p>function apply(code){</p><p>const d=I18N[code]||I18N.en;</p><p>document.documentElement.setAttribute('lang', code);</p><p>document.querySelector('[data-i="title"]').textContent=d.title;</p><p>document.querySelector('[data-i="analyze_title"]').textContent=d.analyze_title;</p><p>document.querySelector('[data-i="legend_line"]').innerHTML=d.legend_line;</p><p>document.querySelectorAll('[data-i="overall"]').forEach(n=&gt; n.textContent=d.overall);</p><p>document.querySelector('[data-i="page_url"]').textContent=<a target="_blank" rel="noopener noreferrer nofollow" href="http://d.page">d.page</a>_url;</p><p>document.querySelectorAll('[data-i="analyze"]').forEach(n=&gt; n.textContent=d.analyze);</p><p>document.querySelectorAll('[data-i="print"]').forEach(n=&gt; n.textContent=d.print);</p><p>document.querySelectorAll('[data-i="reset"]').forEach(n=&gt; n.textContent=d.reset);</p><p>document.querySelectorAll('[data-i="auto_check"]').forEach(n=&gt; n.textContent=<a target="_blank" rel="noopener noreferrer nofollow" href="http://d.auto">d.auto</a>_check);</p><p>localStorage.setItem('lang', code);</p><p>}</p><p>dockBtn.addEventListener('click', ()=&gt; <a target="_blank" rel="noopener noreferrer nofollow" href="http://panel.style">panel.style</a>.display = <a target="_blank" rel="noopener noreferrer nofollow" href="http://panel.style">panel.style</a>.display==='block' ? 'none' : 'block');</p><p>panel.addEventListener('click', (e)=&gt;{ const it=<a target="_blank" rel="noopener noreferrer nofollow" href="http://e.target">e.target</a>.closest('.lang-item'); if(!it) return; apply(it.dataset.code); <a target="_blank" rel="noopener noreferrer nofollow" href="http://panel.style">panel.style</a>.display='none'; });</p><p>fill(); apply(localStorage.getItem('lang')||'en');</p><p>})();</p><p>/* ---------- wireframe bg ---------- */</p><p>(function(){</p><p>const bc = document.getElementById('brainCanvas'), bctx = bc.getContext('2d');</p><p>let bw, bh, pts=[]; function rs(){bw= bc.width = innerWidth; bh= bc.height = innerHeight; pts = Array.from({length:80},()=&gt;({x:Math.random()*bw,y:Math.random()*bh,vx:(Math.random()-.5)*.4,vy:(Math.random()-.5)*.4}))}</p><p>addEventListener('resize',rs,{passive:true}); rs();</p><p>(function loop(){ bctx.clearRect(0,0,bw,bh); for(const p of pts){ p.x+=p.vx; p.y+=p.vy; if(p.x&lt;0||p.x&gt;bw) p.vx*=-1; if(p.y&lt;0||p.y&gt;bh) p.vy*=-1; }</p><p>for(let i=0;i&lt;pts.length;i++){ for(let j=i+1;j&lt;pts.length;j++){ const a=pts[i],b=pts[j]; const d=Math.hypot(a.x-b.x,bh? a.y-b.y:0); if(d&lt;140){ const al=(1-d/140)*0.45; bctx.strokeStyle<code>rgba(157,92,255,${al})</code>; bctx.beginPath(); bctx.moveTo(a.x,a.y); bctx.lineTo(b.x,b.y); bctx.stroke(); } } } requestAnimationFrame(loop); })();</p><p>})();</p><p>/* ---------- Back to Top ---------- */</p><p>(function(){</p><p>const btn = document.getElementById('backTop'); const link = document.getElementById('toTopLink');</p><p>function onScroll(){ <a target="_blank" rel="noopener noreferrer nofollow" href="http://btn.style">btn.style</a>.display = window.scrollY&gt;300 ? 'grid' : 'none'; }</p><p>addEventListener('scroll', onScroll, {passive:true}); onScroll();</p><p>const goTop = e =&gt; { e &amp;&amp; e.preventDefault(); window.scrollTo({top:0,behavior:'smooth'}); };</p><p>btn.addEventListener('click', goTop); link.addEventListener('click', goTop);</p><p>})();</p><p>/* ---------- Helpers ---------- */</p><p>function setChipTone(el, value){</p><p>if (!el) return;</p><p>el.classList.remove('chip-good','chip-mid','chip-bad');</p><p>const ico = el.querySelector('i.ico'); if (ico) ico.classList.remove('ico-green','ico-orange','ico-red','ico-purple');</p><p>const v = Number(value); if (Number.isNaN(v)) return;</p><p>if (v &gt;= 80){ el.classList.add('chip-good'); if (ico) ico.classList.add('ico-green'); }</p><p>else if (v &gt;= 60){ el.classList.add('chip-mid'); if (ico) ico.classList.add('ico-orange'); }</p><p>else { el.classList.add('chip-bad'); if (ico) ico.classList.add('ico-red'); }</p><p>}</p><p>function setText(id, val){ const el = document.getElementById(id); if (el) el.textContent = val; return el; }</p><p>/* ---------- Score Gauge controller ---------- */</p><p>const GAUGE = { rect:null, stop1:null, stop2:null, r1:null, r2:null, arc:null, text:null, H:200, CIRC: 2*Math.PI*95 };</p><p>function setScoreWheel(value){</p><p>if (!GAUGE.rect){</p><p>GAUGE.rect = document.getElementById('scoreClipRect');</p><p>GAUGE.stop1 = document.getElementById('scoreStop1');</p><p>GAUGE.stop2 = document.getElementById('scoreStop2');</p><p>GAUGE.r1 = document.getElementById('ringStop1');</p><p>GAUGE.r2 = document.getElementById('ringStop2');</p><p>GAUGE.arc = document.getElementById('ringArc');</p><p>GAUGE.text = document.getElementById('overallScore');</p><p>if (GAUGE.arc){</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://GAUGE.arc.style">GAUGE.arc.style</a>.strokeDasharray = GAUGE.CIRC.toFixed(2);</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://GAUGE.arc.style">GAUGE.arc.style</a>.strokeDashoffset = GAUGE.CIRC.toFixed(2);</p><p>}</p><p>}</p><p>const v = Math.max(0, Math.min(100, Number(value)||0));</p><p>const y = GAUGE.H - (GAUGE.H * (v/100));</p><p>GAUGE.rect &amp;&amp; GAUGE.rect.setAttribute('y', String(y));</p><p>GAUGE.text &amp;&amp; (GAUGE.text.textContent = Math.round(v) + '%');</p><p>let c1, c2;</p><p>if (v &gt;= 80){ c1='#22c55e'; c2='#16a34a'; }</p><p>else if (v &gt;= 60){ c1='#f59e0b'; c2='#fb923c'; }</p><p>else { c1='#ef4444'; c2='#b91c1c'; }</p><p>GAUGE.stop1 &amp;&amp; GAUGE.stop1.setAttribute('stop-color', c1);</p><p>GAUGE.stop2 &amp;&amp; GAUGE.stop2.setAttribute('stop-color', c2);</p><p>GAUGE.r1 &amp;&amp; GAUGE.r1.setAttribute('stop-color', c1);</p><p>GAUGE.r2 &amp;&amp; GAUGE.r2.setAttribute('stop-color', c2);</p><p>if (GAUGE.arc){</p><p>const offset = GAUGE.CIRC * (1 - (v/100));</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://GAUGE.arc.style">GAUGE.arc.style</a>.strokeDashoffset = offset.toFixed(2);</p><p>}</p><p>setText('overallScoreInline', Math.round(v));</p><p>setChipTone(document.getElementById('overallChip'), v);</p><p>}</p><p>/* ---------- Social buttons effects (burst + ripple) ---------- */</p><p>(function(){</p><p>const dock = document.getElementById('shareDock');</p><p>function fxBurstFrom(el, count=14, hueOffset=0){</p><p>const rect = el.getBoundingClientRect();</p><p>const cx = rect.left + rect.width/2, cy = <a target="_blank" rel="noopener noreferrer nofollow" href="http://rect.top">rect.top</a> + rect.height/2;</p><p>const wrap = document.createElement('div'); wrap.className='fx-burst'; document.body.appendChild(wrap);</p><p>for(let i=0;i&lt;count;i++){</p><p>const sp = document.createElement('div'); sp.className='fx-spark';</p><p>const ang = (Math.PI*2) <em>(i/count) + Math.random()</em>0.6, dist = 30 + Math.random()*70;</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://sp.style">sp.style</a>.left = cx + 'px'; <a target="_blank" rel="noopener noreferrer nofollow" href="http://sp.style.top">sp.style.top</a> = cy + 'px';</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://sp.style">sp.style</a>.setProperty('--dx', (Math.cos(ang)*dist)+'px');</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://sp.style">sp.style</a>.setProperty('--dy', (Math.sin(ang)*dist)+'px');</p><p>const hue = (hueOffset + i*30) % 360;</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://sp.style">sp.style</a>.background = <code>radial-gradient(circle at 30% 30%, #fff, rgba(255,255,255,.2) 40%, hsla(${hue}, 90%, 60%, 0) 70%)</code>;</p><p>wrap.appendChild(sp);</p><p>}</p><p>setTimeout(()=&gt; wrap.remove(), 820);</p><p>}</p><p>function ripple(e, el){</p><p>const r = document.createElement('span');</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://r.style">r.style</a>.cssText = 'position:absolute;border-radius:50%;pointer-events:none;transform:translate(-50%,-50%);background:radial-gradient(circle, rgba(255,255,255,.45) 0%, rgba(255,255,255,.15) 40%, rgba(255,255,255,0) 70%);width:10px;height:10px;animation:r .7s ease-out forwards;z-index:2';</p><p>const rect = el.getBoundingClientRect();</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://r.style">r.style</a>.left = (e.clientX - rect.left) + 'px'; <a target="_blank" rel="noopener noreferrer nofollow" href="http://r.style.top">r.style.top</a> = (e.clientY - <a target="_blank" rel="noopener noreferrer nofollow" href="http://rect.top">rect.top</a>) + 'px';</p><p>el.appendChild(r);</p><p>r.addEventListener('animationend', ()=&gt; r.remove());</p><p>}</p><p>const style = document.createElement('style'); style.textContent='@keyframes r{to{width:220px;height:220px;opacity:0}}'; document.head.appendChild(style);</p><p>dock.addEventListener('click', e=&gt;{</p><p>const btn = <a target="_blank" rel="noopener noreferrer nofollow" href="http://e.target">e.target</a>.closest('.share-btn'); if (!btn) return;</p><p>ripple(e, btn);</p><p>const hue = btn.classList.contains('share-fb') ? 220 :</p><p>btn.classList.contains('share-x') ? 0 :</p><p>btn.classList.contains('share-ln') ? 200 :</p><p>btn.classList.contains('share-wa') ? 140 : 10;</p><p>fxBurstFrom(btn, 16, hue);</p><p>});</p><p>// Build share URLs</p><p>const url = encodeURIComponent(location.href);</p><p>const title = encodeURIComponent(document.title);</p><p>document.getElementById('shareFb').href = <code>https://www.facebook.com/sharer/sharer.php?u=${url}</code>;</p><p>document.getElementById('shareX').href = <code>https://twitter.com/intent/tweet?url=${url}&amp;text=${title}</code>;</p><p>document.getElementById('shareLn').href = <code>https://www.linkedin.com/shareArticle?mini=true&amp;url=${url}&amp;title=${title}</code>;</p><p>document.getElementById('shareWa').href = <code>https://api.whatsapp.com/send?text=${title}%20${url}</code>;</p><p>document.getElementById('shareEm').href = <code>mailto:?subject=${title}&amp;body=${url}</code>;</p><p>const nat = document.getElementById('shareNative');</p><p>if(nat){ nat.addEventListener('click', async ()=&gt;{ try{ if(navigator.share){ await navigator.share({ title: document.title, url: location.href }); } else { <a target="_blank" rel="noopener noreferrer nofollow" href="http://window.open">window.open</a><code>https://twitter.com/intent/tweet?url=${url}&amp;text=${title}</code>,'_blank'); } }catch(e){} }); }</p><p>})();</p><p>/* ---------- Per-category smoke ---------- */</p><p>const CatSmoke = (function(){</p><p>const canvases = [];</p><p>function attachAll(){</p><p>document.querySelectorAll('.cat-smoke').forEach((cv, i)=&gt;{</p><p>const ctx = cv.getContext('2d');</p><p>const o = { el: cv, ctx, parts: [], ratio: 0, dpr: Math.min(2, window.devicePixelRatio||1) };</p><p>resizeOne(o); canvases[i] = o;</p><p>});</p><p>}</p><p>function resizeOne(o){</p><p>const w = o.el.clientWidth || 600, h = o.el.clientHeight || 26;</p><p>o.el.width = Math.max(1, Math.floor(w * o.dpr));</p><p>o.el.height = Math.max(1, Math.floor(h * o.dpr));</p><p>o.ctx.setTransform(o.dpr,0,0,o.dpr,0,0);</p><p>}</p><p>function spawn(o, n=2){</p><p>const W = o.el.clientWidth || 600; const H = o.el.clientHeight || 26;</p><p>const span = Math.max(8, W <em>o.ratio); const baseY = H </em>0.55;</p><p>for(let i=0;i&lt;n;i++){</p><p>const x = Math.random() * span;</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://o.parts">o.parts</a>.push({ x, y: baseY + (Math.random()*2 - 1), vx:(Math.random()-.5)*.30, vy: -(.25 + Math.random()*.45),</p><p>life:1, decay: .03 + Math.random()*.05, r: 1.2 + Math.random()*2.6, hue: 180 + Math.random()*120 });</p><p>}</p><p>}</p><p>function tick(){</p><p>for(const o of canvases){</p><p>if (!o) continue; const W = o.el.clientWidth || 600, H = o.el.clientHeight || 26;</p><p>o.ctx.clearRect(0,0,W,H); o.ctx.globalCompositeOperation = 'lighter';</p><p>const intensity = 40 <em>(0.25 + 0.75 </em>o.ratio); if (<a target="_blank" rel="noopener noreferrer nofollow" href="http://o.parts">o.parts</a>.length &lt; intensity) spawn(o, 2);</p><p>for(const p of <a target="_blank" rel="noopener noreferrer nofollow" href="http://o.parts">o.parts</a>){</p><p>p.x += p.vx; p.y += p.vy; p.vy -= 0.0018; <a target="_blank" rel="noopener noreferrer nofollow" href="http://p.life">p.life</a> -= p.decay; const a = Math.max(0, <a target="_blank" rel="noopener noreferrer nofollow" href="http://p.life">p.life</a>);</p><p>const g = o.ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.r);</p><p>g.addColorStop(0, <code>hsla(${p.hue}, 80%, 70%, ${0.28*a})</code>); g.addColorStop(1, <code>hsla(${(p.hue+60)%360}, 90%, 55%, 0)</code>);</p><p>o.ctx.fillStyle = g; o.ctx.beginPath(); o.ctx.arc(p.x, p.y, p.r, 0, Math.PI*2); o.ctx.fill();</p><p>}</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://o.parts">o.parts</a> = <a target="_blank" rel="noopener noreferrer nofollow" href="http://o.parts">o.parts</a>.filter(p =&gt; <a target="_blank" rel="noopener noreferrer nofollow" href="http://p.life">p.life</a> &gt; 0 &amp;&amp; p.y &gt; -10);</p><p>}</p><p>requestAnimationFrame(tick);</p><p>}</p><p>window.addEventListener('resize', ()=&gt; canvases.forEach(o=&gt;o&amp;&amp;resizeOne(o)), {passive:true});</p><p>attachAll(); requestAnimationFrame(tick);</p><p>return { setPct(i, pct){ const o=canvases[i]; if(!o) return; o.ratio=Math.max(0,Math.min(1,(pct||0)/100)); } };</p><p>})();</p><p>/* ---------- COMPLETION Smoke ---------- */</p><p>const CompSmoke = (function(){</p><p>const cv = document.getElementById('compSmoke'); const ctx = cv?.getContext('2d');</p><p>if (!cv || !ctx) return { setPct(){} };</p><p>let ratio=0, dpr=Math.min(2, window.devicePixelRatio||1), parts=[];</p><p>function resize(){ const w=cv.clientWidth||600, h=cv.clientHeight||140; cv.width=Math.floor(w*dpr); cv.height=Math.floor(h*dpr); ctx.setTransform(dpr,0,0,dpr,0,0); }</p><p>function spawn(n=4){</p><p>const W=cv.clientWidth||600, H=cv.clientHeight||140, span = Math.max(12, W*ratio), baseY=H*0.55;</p><p>for(let i=0;i&lt;n;i++){</p><p>const x = Math.random()*span;</p><p>parts.push({x,y:baseY+(Math.random()*2-1),vx:(Math.random()-.5)*.35,vy:-(.25+Math.random()*.45),</p><p>life:1,decay:.02+Math.random()*.04,r:1.6+Math.random()*3.2,hue:160+Math.random()*140});</p><p>}</p><p>}</p><p>function loop(){</p><p>const W=cv.clientWidth||600, H=cv.clientHeight||140;</p><p>ctx.clearRect(0,0,W,H); ctx.globalCompositeOperation='lighter';</p><p>if (parts.length &lt; 200*ratio) spawn(6);</p><p>for(const p of parts){</p><p>p.x+=p.vx; p.y+=p.vy; p.vy-=0.002; <a target="_blank" rel="noopener noreferrer nofollow" href="http://p.life">p.life</a>-=p.decay; const a=Math.max(0,<a target="_blank" rel="noopener noreferrer nofollow" href="http://p.life">p.life</a>);</p><p>const g=ctx.createRadialGradient(p.x,p.y,0,p.x,p.y,p.r);</p><p>g.addColorStop(0<code>hsla(${p.hue},80%,70%,${0.3*a})</code>); g.addColorStop(1<code>hsla(${(p.hue+60)%360},90%,55%,0)</code>);</p><p>ctx.fillStyle=g; ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,Math.PI*2); ctx.fill();</p><p>}</p><p>parts = parts.filter(p=&gt;<a target="_blank" rel="noopener noreferrer nofollow" href="http://p.life">p.life</a>&gt;0 &amp;&amp; p.y&gt;-20);</p><p>requestAnimationFrame(loop);</p><p>}</p><p>window.addEventListener('resize', resize, {passive:true}); resize(); requestAnimationFrame(loop);</p><p>return { setPct(p){ ratio=Math.max(0,Math.min(1,p/100)); } };</p><p>})();</p><p>/* ---------- Checklist + scoring ---------- */</p><p>(function () {</p><p>const STORAGE_KEY = 'semanticSeoChecklistV6';</p><p>const total = 25;</p><p>const cards = () =&gt; Array.from(document.querySelectorAll('.category-card'));</p><p>const boxes = () =&gt; Array.from(document.querySelectorAll('#analyzer input[type="checkbox"]'));</p><p>const contentScoreInline = document.getElementById('contentScoreInline');</p><p>let lastAnalyzed = 0;</p><p>const CAT_PALETTES = [</p><p>['#22d3ee','#a78bfa'],</p><p>['#34d399','#60a5fa'],</p><p>['#fcd34d','#fb7185'],</p><p>['#86efac','#f0abfc'],</p><p>['#fca5a5','#fde68a'],</p><p>['#f472b6','#60a5fa'],</p><p>];</p><p>function contentScore(){ const checked = boxes().filter(cb=&gt;cb.checked).length; return Math.round((checked/total)*100); }</p><p>function overallScoreBlended(){</p><p>const cs = contentScore();</p><p>if (cs===100) return 100;</p><p>return Math.round( Math.max(lastAnalyzed, (lastAnalyzed*0.6 + cs*0.4)) );</p><p>}</p><p>// ===== Completion water controller =====</p><p>const compRect = document.getElementById('compClipRect');</p><p>const compStop1 = document.getElementById('compStop1');</p><p>const compStop2 = document.getElementById('compStop2');</p><p>const compPct = document.getElementById('compPct');</p><p>const compBar = document.getElementById('compWater');</p><p>function setCompletion(vPct){</p><p>const v = Math.max(0, Math.min(100, vPct|0));</p><p>const width = Math.round(600 * v / 100);</p><p>if (compRect) compRect.setAttribute('width', String(width));</p><p>if (compBar) compBar.setAttribute('aria-valuenow', v);</p><p>if (compPct) compPct.textContent = v + '%';</p><p>// color: ≥80 green, 60–79 orange, &lt;60 red</p><p>let c1,c2;</p><p>if (v &gt;= 80){ c1='#22c55e'; c2='#16a34a'; }</p><p>else if (v &gt;= 60){ c1='#f59e0b'; c2='#fb923c'; }</p><p>else { c1='#ef4444'; c2='#b91c1c'; }</p><p>compStop1?.setAttribute('stop-color', c1);</p><p>compStop2?.setAttribute('stop-color', c2);</p><p>// smoke intensity by ratio</p><p>if (window.CompSmoke &amp;&amp; typeof CompSmoke.setPct === 'function') CompSmoke.setPct(v);</p><p>}</p><p>function updateCatHeadingBars(){</p><p>cards().forEach((card, idx)=&gt;{</p><p>const all = card.querySelectorAll('input[type="checkbox"]');</p><p>const done = card.querySelectorAll('input[type="checkbox"]:checked');</p><p>const pct = all.length ? Math.round((done.length / all.length) * 100) : 0;</p><p>card.querySelector('.checked-count').textContent = done.length;</p><p>card.querySelector('.total-count').textContent = all.length;</p><p>const rect = document.getElementById<code>catFillRect-${idx}</code>);</p><p>const pctEl = document.getElementById<code>catPct-${idx}</code>);</p><p>if (rect) rect.setAttribute('width', String(Math.round(600 * pct / 100)));</p><p>if (pctEl) pctEl.textContent = <code>${done.length}/${all.length} • ${pct}%</code>;</p><p>const [c1,c2] = CAT_PALETTES[idx % CAT_PALETTES.length];</p><p>const stop1 = document.getElementById<code>catStop1-${idx}</code>);</p><p>const stop2 = document.getElementById<code>catStop2-${idx}</code>);</p><p>if (stop1 &amp;&amp; stop2){ stop1.setAttribute('stop-color', c1); stop2.setAttribute('stop-color', c2); }</p><p>if (window.CatSmoke &amp;&amp; typeof CatSmoke.setPct === 'function') CatSmoke.setPct(idx, pct);</p><p>});</p><p>}</p><p>function update(){</p><p>const checked = boxes().filter(cb=&gt;cb.checked).length;</p><p>const pct = Math.round((checked/total)*100);</p><p>document.getElementById('progressCaption').textContent = <code>${checked} of ${total} items completed</code>;</p><p>updateCatHeadingBars();</p><p>setCompletion(pct);</p><p>const cs = contentScore(); contentScoreInline.textContent = cs;</p><p>setChipTone(document.getElementById('contentScoreChip'), cs);</p><p>setScoreWheel( overallScoreBlended() );</p><p>}</p><p>function load(){ try{const saved = JSON.parse(localStorage.getItem(STORAGE_KEY)||'[]'); boxes().forEach(cb=&gt;cb.checked = saved.includes(<a target="_blank" rel="noopener noreferrer nofollow" href="http://cb.id">cb.id</a>));}catch(e){} update(); }</p><p>function save(){ const ids = boxes().filter(cb=&gt;cb.checked).map(cb=&gt;<a target="_blank" rel="noopener noreferrer nofollow" href="http://cb.id">cb.id</a>); localStorage.setItem(STORAGE_KEY, JSON.stringify(ids)); }</p><p>document.addEventListener('change', (e)=&gt;{ if(<a target="_blank" rel="noopener noreferrer nofollow" href="http://e.target">e.target</a>.matches('#analyzer input[type="checkbox"]')){ update(); save(); }});</p><p>document.getElementById('resetChecklist').addEventListener('click', ()=&gt;{ if(!confirm('Reset the checklist?')) return; localStorage.removeItem(STORAGE_KEY); boxes().forEach(cb=&gt;cb.checked=false); for(let i=1;i&lt;=25;i++){ setScoreBadge(i,null);} lastAnalyzed=0; setScoreWheel(0); update(); });</p><p>document.getElementById('printChecklist').addEventListener('click', ()=&gt; window.print());</p><p>document.getElementById('printTop').addEventListener('click', ()=&gt; window.print());</p><p>document.getElementById('exportChecklist').addEventListener('click', (e)=&gt;{</p><p>e.preventDefault();</p><p>const data = { checked: boxes().filter(cb=&gt;cb.checked).map(cb=&gt;<a target="_blank" rel="noopener noreferrer nofollow" href="http://cb.id">cb.id</a>), ts: <a target="_blank" rel="noopener noreferrer nofollow" href="http://Date.now">Date.now</a>(), v: 1 };</p><p>const blob = new Blob([JSON.stringify(data,null,2)], {type:'application/json'});</p><p>const a = document.createElement('a'); a.href = URL.createObjectURL(blob); <a target="_blank" rel="noopener noreferrer nofollow" href="http://a.download">a.download</a>='semantic-seo-checklist.json'; <a target="_blank" rel="noopener noreferrer nofollow" href="http://a.click">a.click</a>(); URL.revokeObjectURL(a.href);</p><p>});</p><p>document.getElementById('importChecklist').addEventListener('click', (e)=&gt;{ e.preventDefault(); document.getElementById('importFile').click(); });</p><p>document.getElementById('importFile').addEventListener('change', async (e)=&gt;{</p><p>const file = <a target="_blank" rel="noopener noreferrer nofollow" href="http://e.target">e.target</a>.files?.[0]; if(!file) return;</p><p>try { const text = await file.text(); const json = JSON.parse(text||'{}'); boxes().forEach(cb=&gt; cb.checked = (json.checked||[]).includes(<a target="_blank" rel="noopener noreferrer nofollow" href="http://cb.id">cb.id</a>)); save(); update(); } catch(err){ alert('Invalid JSON'); }</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://e.target">e.target</a>.value='';</p><p>});</p><p>// Paint badges + severity</p><p>window.setScoreBadge = (num,score)=&gt;{</p><p>const el=document.getElementById('sc-'+num); if(!el) return;</p><p>el.className='score-badge';</p><p>const row = el.closest('.checklist-item');</p><p>row &amp;&amp; row.classList.remove('sev-good','sev-mid','sev-bad');</p><p>if(score==null){el.textContent='—';return;}</p><p>el.textContent=score;</p><p>if(score&gt;=80){ el.classList.add('score-good'); row &amp;&amp; row.classList.add('sev-good'); }</p><p>else if(score&gt;=60){ el.classList.add('score-mid'); row &amp;&amp; row.classList.add('sev-mid'); }</p><p>else { el.classList.add('score-bad'); row &amp;&amp; row.classList.add('sev-bad'); }</p><p>};</p><p>window.__setAnalyzedScore = function(v){ lastAnalyzed = Math.max(0, Math.min(100, +v||0)); setScoreWheel( overallScoreBlended() ); }</p><p>window.__getContentScore = contentScore;</p><p>window.__updateChecklist = update;</p><p>load();</p><p>})();</p><p>/* ---------- Modal + Improve + FX ---------- */</p><p>(function(){</p><p>const $ = s=&gt;document.querySelector(s);</p><p>const $$ = s=&gt;Array.from(document.querySelectorAll(s));</p><p>const backdrop = $('#modalBackdrop'), modal = $('#tipModal'), closeBtn = $('#modalClose');</p><p>const panes = { tipsTab: $('#tipsTab'), examplesTab: $('#examplesTab'), humanTab: $('#humanTab'), aiTab: $('#aiTab'), fullTab: $('#fullTab') };</p><p>const tabs = $$('.tab');</p><p>function openModal(){ <a target="_blank" rel="noopener noreferrer nofollow" href="http://backdrop.style">backdrop.style</a>.display='block'; <a target="_blank" rel="noopener noreferrer nofollow" href="http://modal.style">modal.style</a>.display='flex'; }</p><p>function closeModal(){ <a target="_blank" rel="noopener noreferrer nofollow" href="http://backdrop.style">backdrop.style</a>.display='none'; <a target="_blank" rel="noopener noreferrer nofollow" href="http://modal.style">modal.style</a>.display='none'; }</p><p>closeBtn.addEventListener('click', closeModal); backdrop.addEventListener('click', closeModal);</p><p>document.addEventListener('keydown', e=&gt;{ if(e.key==='Escape') closeModal(); });</p><p>tabs.forEach(t=&gt; t.addEventListener('click', ()=&gt;{ tabs.forEach(x=&gt;x.classList.remove('active')); Object.values(panes).forEach(p=&gt;p.classList.remove('active')); t.classList.add('active'); panes[<a target="_blank" rel="noopener noreferrer nofollow" href="http://t.dataset.tab">t.dataset.tab</a>].classList.add('active'); }));</p><p>function fxRipple(e, btn){</p><p>const r = document.createElement('span');</p><p>r.className='ripple';</p><p>const rect = btn.getBoundingClientRect();</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://r.style">r.style</a>.left = (e.clientX - rect.left) + 'px';</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://r.style.top">r.style.top</a> = (e.clientY - <a target="_blank" rel="noopener noreferrer nofollow" href="http://rect.top">rect.top</a>) + 'px';</p><p>btn.appendChild(r);</p><p>setTimeout(()=&gt; r.remove(), 700);</p><p>}</p><p>function fxBurstFrom(el, count=14){</p><p>const rect = el.getBoundingClientRect();</p><p>const cx = rect.left + rect.width/2;</p><p>const cy = <a target="_blank" rel="noopener noreferrer nofollow" href="http://rect.top">rect.top</a> + rect.height/2;</p><p>const wrap = document.createElement('div');</p><p>wrap.className='fx-burst';</p><p>document.body.appendChild(wrap);</p><p>for(let i=0;i&lt;count;i++){</p><p>const sp = document.createElement('div');</p><p>sp.className='fx-spark';</p><p>const ang = (Math.PI*2) <em>(i/count) + Math.random()</em>0.6;</p><p>const dist = 40 + Math.random()*80;</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://sp.style">sp.style</a>.left = cx + 'px';</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://sp.style.top">sp.style.top</a> = cy + 'px';</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://sp.style">sp.style</a>.setProperty('--dx', (Math.cos(ang)*dist)+'px');</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://sp.style">sp.style</a>.setProperty('--dy', (Math.sin(ang)*dist)+'px');</p><p><a target="_blank" rel="noopener noreferrer nofollow" href="http://sp.style">sp.style</a>.background = <code>radial-gradient(circle at 30% 30%, #fff, rgba(255,255,255,.2) 40%, hsla(${(i*40)%360}, 90%, 55%, 0) 70%)</code>;</p><p>wrap.appendChild(sp);</p><p>}</p><p>setTimeout(()=&gt; wrap.remove(), 820);</p><p>}</p><p>function flashRow(li){ li.classList.remove('flash-row'); void li.offsetWidth; li.classList.add('flash-row'); }</p><p>document.getElementById('checklistGrid').addEventListener('click', (e)=&gt;{</p><p>const btn = <a target="_blank" rel="noopener noreferrer nofollow" href="http://e.target">e.target</a>.closest('.improve-btn'); if(!btn) return;</p><p>fxRipple(e, btn); fxBurstFrom(btn);</p><p>const li = btn.closest('.checklist-item'); if(li) flashRow(li);</p><p>const id = <a target="_blank" rel="noopener noreferrer nofollow" href="http://btn.dataset.id">btn.dataset.id</a>;</p><p>const idx = parseInt(id.split('-')[1],10);</p><p>const labelEl = btn.parentElement.querySelector('label span');</p><p>const label = labelEl ? labelEl.textContent.trim() : <code>Item ${idx}</code>;</p><p>const tips = (window.__lastSuggestions||{})[id] || ['Run Analyze to get fresh tips for this item.'];</p><p>const ul = document.getElementById('modalList'); ul.innerHTML=''; tips.forEach(t=&gt;{ const li=document.createElement('li'); li.textContent=t; ul.appendChild(li); });</p><p>const q = encodeURIComponent(label + ' SEO examples');</p><p>document.getElementById('examplesPre').innerHTML = <code>Open examples:\nhttps://www.google.com/search?q=${q}\n\nTry site: operators with top competitors.</code>;</p><p>tabs.forEach(x=&gt;x.classList.remove('active')); document.querySelector('[data-tab="tipsTab"]').classList.add('active');</p><p>Object.values(panes).forEach(p=&gt;p.classList.remove('active')); panes.tipsTab.classList.add('active'); openModal();</p><p>});</p><p>document.getElementById('viewAIText').addEventListener('click', ()=&gt; switchTo('aiTab'));</p><p>document.getElementById('viewHumanBtn').addEventListener('click', ()=&gt; switchTo('humanTab'));</p><p>document.getElementById('viewAIBtn').addEventListener('click', ()=&gt; switchTo('aiTab'));</p><p>function switchTo(key){ tabs.forEach(x=&gt;x.classList.remove('active')); document.querySelector<code>[data-tab="${key}"]</code>).classList.add('active'); Object.values(panes).forEach(p=&gt;p.classList.remove('active')); panes[key].classList.add('active'); openModal(); }</p><p>window.__setAIData = function(ai){</p><p>const aiSn = ai?.ai_sentences || [];</p><p>const huSn = ai?.human_sentences || [];</p><p>setText('aiSnippetsPre', aiSn.length ? aiSn.join('\n\n') : 'No AI-like snippets detected.');</p><p>setText('humanSnippetsPre', huSn.length ? huSn.join('\n\n') : 'No human-like snippets isolated.');</p><p>setText('fullTextPre', ai?.full_text || 'No text captured.');</p><p>setText('aiPct', (typeof ai?.ai_pct==='number') ? <a target="_blank" rel="noopener noreferrer nofollow" href="http://ai.ai">ai.ai</a>_pct : '—');</p><p>setText('humanPct', (typeof ai?.human_pct==='number') ? ai.human_pct : '—');</p><p>}</p><p>})();</p><p>/* ---------- URL normalization ---------- */</p><p>function normalizeUrl(u){ if(!u) return ''; u = u.trim(); if (!/^https?:\/\//i.test(u)) u = 'https://' + u.replace(/^\/+/, ''); try { new URL(u); } catch(e){} return u; }</p><p>/* ---------- Water Smoke for progress bar ---------- */</p><p>const WaterSmoke = (function(){</p><p>const canvas = document.getElementById('waterSmoke');</p><p>const ctx = canvas ? canvas.getContext('2d') : null;</p><p>let running = false, particles = [], frameId = 0;</p><p>let levelRatioTop = 1;</p><p>function cssW(){ return canvas?.clientWidth || canvas?.parentElement?.clientWidth || 0; }</p><p>function cssH(){ return canvas?.clientHeight || canvas?.parentElement?.clientHeight || 0; }</p><p>function resize(){ if(!canvas || !ctx) return; const dpr = Math.min(2, window.devicePixelRatio||1); const w = cssW(), h = cssH(); canvas.width = Math.max(1, Math.floor(w <em>dpr)); canvas.height = Math.max(1, Math.floor(h </em>dpr)); ctx.setTransform(dpr,0,0,dpr,0,0); }</p><p>function spawn(n=6){</p><p>if(!canvas) return; const y = cssH() * levelRatioTop;</p><p>for(let i=0;i&lt;n;i++){ const x = Math.random()*cssW(); const jitter=(Math.random()*4-2); const speed = 0.4 + Math.random()*0.8;</p><p>particles.push({ x, y:y+jitter, vx:(Math.random()-.5)*.35, vy:-speed, life:1, decay:0.008+Math.random()*0.02, r:2+Math.random()*6, hue:(180+Math.random()*120) });</p><p>}</p><p>}</p><p>function tick(){</p><p>if(!running || !ctx || !canvas){ cancelAnimationFrame(frameId); return; }</p><p>frameId = requestAnimationFrame(tick);</p><p>ctx.clearRect(0,0,cssW(),cssH()); ctx.globalCompositeOperation = 'lighter';</p><p>if (particles.length &lt; 180) spawn(6);</p><p>for (const p of particles){</p><p>p.x += p.vx; p.y += p.vy; p.vy -= 0.005; <a target="_blank" rel="noopener noreferrer nofollow" href="http://p.life">p.life</a> -= p.decay;</p><p>const a = Math.max(0, <a target="_blank" rel="noopener noreferrer nofollow" href="http://p.life">p.life</a>);</p><p>const g = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.r);</p><p>g.addColorStop(0, <code>hsla(${p.hue}, 80%, 70%, ${0.35*a})</code>);</p><p>g.addColorStop(1, <code>hsla(${(p.hue+60)%360}, 90%, 55%, ${0.05*a})</code>);</p><p>ctx.fillStyle = g; ctx.beginPath(); ctx.arc(p.x, p.y, p.r, 0, Math.PI*2); ctx.fill();</p><p>}</p><p>particles = particles.filter(p=&gt; <a target="_blank" rel="noopener noreferrer nofollow" href="http://p.life">p.life</a>&gt;0 &amp;&amp; p.y &gt; -20);</p><p>}</p><p>function start(){ if(!canvas||!ctx) return; running=true; resize(); cancelAnimationFrame(frameId); frameId = requestAnimationFrame(tick); }</p><p>function stop(){ running=false; cancelAnimationFrame(frameId); particles.length = 0; if(ctx) ctx.clearRect(0,0,cssW(),cssH()); }</p><p>function setLevel(topRatio){ levelRatioTop = Math.max(0, Math.min(1, topRatio)); }</p><p>window.addEventListener('resize', ()=&gt; running &amp;&amp; resize(), {passive:true});</p><p>return { start, stop, setLevel };</p><p>})();</p><p>/* ---------- Analyze progress controller ---------- */</p><p>const Water = (function(){</p><p>const wrap = document.getElementById('waterWrap');</p><p>const bar = document.getElementById('waterBar');</p><p>const rect = document.getElementById('waterClipRect');</p><p>const pct = document.getElementById('waterPct');</p><p>const label= document.getElementById('pageUrlLabel');</p><p>let prog = 0, intv = null;</p><p>const H = 200;</p><p>function show(){ <a target="_blank" rel="noopener noreferrer nofollow" href="http://wrap.style">wrap.style</a>.display='block'; }</p><p>function hide(){ <a target="_blank" rel="noopener noreferrer nofollow" href="http://wrap.style">wrap.style</a>.display='none'; }</p><p>function set(v){</p><p>prog = Math.max(0, Math.min(100, v));</p><p>const y = H - (H * (prog/100));</p><p>rect.setAttribute('y', String(y));</p><p>bar.setAttribute('aria-valuenow', Math.round(prog));</p><p>pct.textContent = Math.round(prog) + '%';</p><p>if (WaterSmoke &amp;&amp; typeof WaterSmoke.setLevel === 'function') WaterSmoke.setLevel(y / H);</p><p>}</p><p>function start(){</p><p>show(); set(0);</p><p>label.classList.add('animating');</p><p>if (WaterSmoke &amp;&amp; WaterSmoke.start) WaterSmoke.start();</p><p>clearInterval(intv);</p><p>intv = setInterval(()=&gt;{ if (prog &lt; 90) set(prog + 1.2); }, 50);</p><p>}</p><p>function finish(){</p><p>clearInterval(intv);</p><p>const step = ()=&gt;{ if (prog &gt;= 100){</p><p>setTimeout(()=&gt;{ label.classList.remove('animating'); }, 300);</p><p>setTimeout(()=&gt;{ if (WaterSmoke &amp;&amp; WaterSmoke.stop) WaterSmoke.stop(); }, 800);</p><p>return;</p><p>}</p><p>set(prog + Math.max(1.5, (100-prog)*0.12));</p><p>requestAnimationFrame(step);</p><p>};</p><p>requestAnimationFrame(step);</p><p>}</p><p>function reset(){</p><p>clearInterval(intv); set(0); hide(); label.classList.remove('animating');</p><p>if (WaterSmoke &amp;&amp; WaterSmoke.stop) WaterSmoke.stop();</p><p>}</p><p>return { start, finish, reset, set, show, hide };</p><p>})();</p><p>/* ---------- Hue cycler ---------- */</p><p>(function(){ const root=document.documentElement; let start=<a target="_blank" rel="noopener noreferrer nofollow" href="http://performance.now">performance.now</a>(); function frame(now){ const angle=((now-start)/4)%360; <a target="_blank" rel="noopener noreferrer nofollow" href="http://root.style">root.style</a>.setProperty('--hue', angle + 'deg'); requestAnimationFrame(frame);} requestAnimationFrame(frame); })();</p><p>/* ---------- Analyze flow (auto-select from badges ≥80) ---------- */</p><p>(function(){</p><p>const $ = s =&gt; document.querySelector(s);</p><p>const AUTO_SCORE_THRESHOLD = 80;</p><p>const STORAGE_KEY = 'semanticSeoChecklistV6';</p><p>document.getElementById('copyQuick').addEventListener('click', async ()=&gt;{</p><p>const bits = [</p><p><code>HTTP: ${document.getElementById('rStatus')?.textContent||''}</code>,</p><p><code>Title: ${document.getElementById('rTitleLen')?.textContent||''}</code>,</p><p><code>Meta: ${document.getElementById('rMetaLen')?.textContent||''}</code>,</p><p><code>Canon: ${document.getElementById('rCanonical')?.textContent||''}</code>,</p><p><code>Robots: ${document.getElementById('rRobots')?.textContent||''}</code>,</p><p><code>H1/H2/H3: ${document.getElementById('rHeadings')?.textContent||''}</code>,</p><p><code>Internal: ${document.getElementById('rInternal')?.textContent||''}</code>,</p><p><code>Schema: ${document.getElementById('rSchema')?.textContent||''}</code>,</p><p><code>Overall: ${document.getElementById('overallScoreInline')?.textContent||''}/100</code>,</p><p><code>Content: ${document.getElementById('contentScoreInline')?.textContent||''}/100</code>,</p><p><code>AI: ${document.getElementById('aiPct')?.textContent || '—'}% / Human: ${document.getElementById('humanPct')?.textContent || '—'}%</code></p><p>];</p><p>try { await navigator.clipboard.writeText(bits.join('\n')); alert('Report copied!'); } catch(e){ alert('Could not copy'); }</p><p>});</p><p>document.getElementById('analyzeForm').addEventListener('submit', (e)=&gt;{ e.preventDefault(); document.getElementById('analyzeBtn').click(); });</p><p>document.getElementById('analyzeBtn').addEventListener('click', analyze);</p><p>function autoSelectFromRenderedBadges(){</p><p>const picks = new Set();</p><p>for(let i=1;i&lt;=25;i++){</p><p>const badge = document.getElementById('sc-'+i);</p><p>if(!badge) continue;</p><p>const val = parseInt((badge.textContent||'').trim(), 10);</p><p>if(Number.isFinite(val) &amp;&amp; val &gt;= AUTO_SCORE_THRESHOLD){</p><p>picks.add('ck-'+i);</p><p>}</p><p>}</p><p>return picks;</p><p>}</p><p>// Score fallback + coercion helpers</p><p>function computeFallbackScores(data){</p><p>const tLen = Number((data.title||'').length)||0;</p><p>const mLen = Number(data.meta_description_len)||0;</p><p>const canon = !!data.canonical;</p><p>const robots = (data.robots||'')+'';</p><p>const viewport = !!data.viewport;</p><p>const counts = data.counts||{};</p><p>const h1 = Number(counts.h1)||0;</p><p>const h2 = Number(counts.h2)||0;</p><p>const h3 = Number(counts.h3)||0;</p><p>const internal = Number(counts.internal_links)||0;</p><p>const hasSchema = Array.isArray(data.schema?.found_types) &amp;&amp; data.schema.found_types.length&gt;0;</p><p>const hasBreadcrumb = (data.schema?.found_types||[]).includes('BreadcrumbList');</p><p>const titleScore = (tLen&gt;=45 &amp;&amp; tLen&lt;=65)?92:((tLen&gt;=30 &amp;&amp; tLen&lt;=72)?78:45);</p><p>const metaScore = (mLen&gt;=120 &amp;&amp; mLen&lt;=170)?90:((mLen&gt;=80)?70:40);</p><p>const canonScore= canon?90:40;</p><p>const indexScore= /noindex/i.test(robots)?20:82;</p><p>const headingVar = (h2+h3);</p><p>const headScore = headingVar&gt;=6?82:(headingVar&gt;=3?70:55);</p><p>const internalScore = internal&gt;=8?88:(internal&gt;=3?70:40);</p><p>const mobileScore = viewport?88:40;</p><p>const schemaScore = hasSchema?85:45;</p><p>const breadScore = hasBreadcrumb?85:45;</p><p>const fixed = { faq:60, eat:70, read:72, media:70, slug:72, speed:68, vitals:62, cta:70, entity:72, related:70, sameas:60, unique:65, keywords:65, intent:70, h1inc: h1&gt;0?75:55 };</p><p>return {</p><p>'ck-1': fixed.intent, 'ck-2': fixed.keywords, 'ck-3': fixed.h1inc, 'ck-4': fixed.faq, 'ck-5': <a target="_blank" rel="noopener noreferrer nofollow" href="http://fixed.read">fixed.read</a>,</p><p>'ck-6': titleScore, 'ck-7': metaScore, 'ck-8': canonScore, 'ck-9': indexScore,</p><p>'ck-10': <a target="_blank" rel="noopener noreferrer nofollow" href="http://fixed.eat">fixed.eat</a>, 'ck-11': fixed.unique, 'ck-12': 70, 'ck-13': <a target="_blank" rel="noopener noreferrer nofollow" href="http://fixed.media">fixed.media</a>, 'ck-14': headScore,</p><p>'ck-15': internalScore, 'ck-16': fixed.slug, 'ck-17': breadScore, 'ck-18': mobileScore,</p><p>'ck-19': fixed.speed, 'ck-20': fixed.vitals, 'ck-21': fixed.cta, 'ck-22': fixed.entity, 'ck-23': fixed.related,</p><p>'ck-24': schemaScore, 'ck-25': fixed.sameas</p><p>};</p><p>}</p><p>function coerceScoresToMap(scores){</p><p>const out = {};</p><p>if (!scores) return out;</p><p>const ck = Object.keys(scores).filter(k=&gt;/^ck-\d+$/.test(k));</p><p>if (ck.length){ ck.forEach(k=&gt; out[k] = Number(scores[k])); return out; }</p><p>if (Array.isArray(scores)){ for (let i=0;i&lt;Math.min(25, scores.length);i++) out['ck-'+(i+1)] = Number(scores[i]); return out; }</p><p>const keys = Object.keys(scores);</p><p>if (keys.every(k=&gt;/^\d+$/.test(k))){ keys.forEach(k=&gt; out['ck-'+k] = Number(scores[k])); return out; }</p><p>return out;</p><p>}</p><p>async function analyze(){</p><p>const url = normalizeUrl(document.getElementById('analyzeUrl').value);</p><p>const status = document.getElementById('analyzeStatus');</p><p>const btn = document.getElementById('analyzeBtn');</p><p>const report = document.getElementById('analyzeReport');</p><p>if (!url){ if(status) status.textContent = 'Please enter a URL.'; Water.reset(); return; }</p><p>if(status) status.textContent = 'Analyzing…';</p><p>btn.disabled = true; btn.innerHTML = '&lt;i class="fa-solid fa-spinner fa-spin"&gt;&lt;/i&gt; Analyzing';</p><p>Water.start();</p><p>let data;</p><p>try{</p><p>const resp = await fetch('{{ route('analyze.json') }}', {</p><p>method:'POST',</p><p>headers:{'Content-Type':'application/json','X-CSRF-TOKEN': document.querySelector('meta[name="csrf-token"]').content},</p><p>body: JSON.stringify({ url })</p><p>});</p><p>data = await resp.json();</p><p>}catch(err){</p><p>if (status) status.textContent = 'Network error';</p><p>Water.finish();</p><p>btn.disabled = false; btn.innerHTML = '&lt;i class="fa-solid fa-magnifying-glass"&gt;&lt;/i&gt; Analyze';</p><p>return;</p><p>}</p><p>try{</p><p>setText('rStatus', data.status);</p><p>setText('rTitleLen', (data.title || '').length);</p><p>setText('rMetaLen', data.meta_description_len);</p><p>setText('rCanonical', data.canonical ? 'Yes' : 'No');</p><p>setText('rRobots', data.robots || '—');</p><p>setText('rViewport', data.viewport ? 'Yes' : 'No');</p><p>setText('rHeadings', <code>${data.counts?.h1||0}/${data.counts?.h2||0}/${data.counts?.h3||0}</code>);</p><p>setText('rInternal', data.counts?.internal_links ?? 0);</p><p>setText('rSchema', (data.schema?.found_types || []).slice(0,6).join(', ') || '—');</p><p>setText('rAutoCount', (<a target="_blank" rel="noopener noreferrer nofollow" href="http://data.auto">data.auto</a>_check_ids||[]).length);</p><p>if (report) <a target="_blank" rel="noopener noreferrer nofollow" href="http://report.style">report.style</a>.display='block';</p><p>window.__lastSuggestions = data.suggestions || {};</p><p>// unify scores</p><p>let scoreMap = coerceScoresToMap(data.scores || data.checklist_scores || data.checklist || data.items);</p><p>if (!Object.keys(scoreMap).length) scoreMap = computeFallbackScores(data);</p><p>for (let i=1;i&lt;=25;i++){</p><p>const v = Number(scoreMap['ck-'+i]);</p><p>setScoreBadge(i, Number.isFinite(v)?v:null);</p><p>}</p><p>// AI/Human UI</p><p>const ai = <a target="_blank" rel="noopener noreferrer nofollow" href="http://data.ai">data.ai</a>_detection || {};</p><p>const badge = document.getElementById('aiBadge');</p><p>if (badge){</p><p>badge.classList.remove('chip-good','chip-mid','chip-bad');</p><p>const labelMap={likely_human:'Likely Human', mixed:'Mixed', likely_ai:'Likely AI'};</p><p>const iconMap={likely_human:'fa-user-check', mixed:'fa-shuffle', likely_ai:'fa-robot'};</p><p>const colorMap={likely_human:'ico-green', mixed:'ico-orange', likely_ai:'ico-red'};</p><p>const chipMap={likely_human:'chip-good', mixed:'chip-mid', likely_ai:'chip-bad'};</p><p>const key = (ai.label||'').toLowerCase();</p><p>const label = labelMap[key] || 'Unknown';</p><p>const icon = iconMap[key] || 'fa-user';</p><p>const icoC = colorMap[key] || 'ico-purple';</p><p>const chipC = chipMap[key];</p><p>const conf = (typeof ai.likelihood==='number') ? <code>(${ai.likelihood}%)</code> : '';</p><p>const aiStr = (typeof <a target="_blank" rel="noopener noreferrer nofollow" href="http://ai.ai">ai.ai</a>_pct==='number') ? <code>— ${ai.ai_pct}% AI-like</code> : '';</p><p>const humanStr = (typeof ai.human_pct==='number') ? <code>— ${ai.human_pct}% Human</code> : '';</p><p>badge.innerHTML = <code>&lt;i class="fa-solid ${icon} ico ${icoC}"&gt;&lt;/i&gt; Writer: &lt;b&gt;${label}${conf}${aiStr}${humanStr}&lt;/b&gt;</code>;</p><p>if (chipC) badge.classList.add(chipC);</p><p>setText('aiPct', (typeof <a target="_blank" rel="noopener noreferrer nofollow" href="http://ai.ai">ai.ai</a>_pct==='number') ? <a target="_blank" rel="noopener noreferrer nofollow" href="http://ai.ai">ai.ai</a>_pct : '—');</p><p>setText('humanPct', (typeof ai.human_pct==='number') ? ai.human_pct : '—');</p><p>if (window.__setAIData) window.__setAIData(ai);</p><p>}</p><p>// Overall score -&gt; wheel</p><p>const backendOverall = typeof data.overall_score === 'number' ? data.overall_score : (()=&gt;{</p><p>let sum=0,n=0; for(let i=1;i&lt;=25;i++){ const v=Number(scoreMap['ck-'+i]); if(Number.isFinite(v)){sum+=v;n++;}}</p><p>return n?Math.round(sum/n):0;</p><p>})();</p><p>if (window.__setAnalyzedScore) window.__setAnalyzedScore(backendOverall);</p><p>// Auto-apply based on badges</p><p>if (document.getElementById('autoApply').checked) {</p><p>const fromBadges = autoSelectFromRenderedBadges();</p><p>const union = new Set([...(<a target="_blank" rel="noopener noreferrer nofollow" href="http://data.auto">data.auto</a>_check_ids||[]), ...fromBadges]);</p><p>const all = document.querySelectorAll('#analyzer input[type="checkbox"]');</p><p>all.forEach(cb =&gt; cb.checked = union.has(<a target="_blank" rel="noopener noreferrer nofollow" href="http://cb.id">cb.id</a>));</p><p>const selected = Array.from(all).filter(cb=&gt;cb.checked).map(cb=&gt;<a target="_blank" rel="noopener noreferrer nofollow" href="http://cb.id">cb.id</a>);</p><p>localStorage.setItem(STORAGE_KEY, JSON.stringify(selected));</p><p>}</p><p>if (window.__updateChecklist) window.__updateChecklist();</p><p>const csNow = window.__getContentScore ? window.__getContentScore() : 0;</p><p>setText('contentScoreInline', csNow);</p><p>setChipTone(document.getElementById('contentScoreChip'), csNow);</p><p>Water.finish();</p><p>const wheel = parseInt(document.getElementById('overallScoreInline').textContent||'0',10);</p><p>if (status) status.textContent = wheel&gt;=80 ? 'Great! You passed—keep going.' : (wheel&lt;60 ? 'Score is low — optimize and re-Analyze.' : 'Solid! Improve a few items to hit green.');</p><p>setTimeout(()=&gt; { if(status) status.textContent=''; }, 4200);</p><p>} catch(e){</p><p>console.error(e);</p><p>if (status) status.textContent = 'Error: '+e.message;</p><p>Water.finish();</p><p>} finally {</p><p>btn.disabled = false; btn.innerHTML = '&lt;i class="fa-solid fa-magnifying-glass"&gt;&lt;/i&gt; Analyze';</p><p>}</p><p>}</p><p>})();</p><p>/* ---------- Background smoke (WebGL2) ---------- */</p><p>(function(){</p><p>const canvas = document.getElementById('smokeFX'); if (!canvas) return;</p><p>const dpr = Math.min(2, window.devicePixelRatio || 1);</p><p>let gl = null, start=<a target="_blank" rel="noopener noreferrer nofollow" href="http://performance.now">performance.now</a>();</p><p>function resize(){ canvas.width = Math.floor(innerWidth*dpr); canvas.height=Math.floor(innerHeight*dpr); if (gl) gl.viewport(0,0,canvas.width,canvas.height); }</p><p>addEventListener('resize', resize, {passive:true}); resize();</p><p>try { gl = canvas.getContext('webgl2', { alpha:true, antialias:false, depth:false, stencil:false }); } catch(e){}</p><p>if (!gl) return;</p><p>const vs=`#version 300 es</p><p>precision highp float; const vec2 v[3]=vec2[3](vec2(-1.,-1.),vec2(3.,-1.),vec2(-1.,3.));</p><p>out vec2 uv; void main(){ vec2 p=v[gl_VertexID]; uv=.5*(p+1.); gl_Position=vec4(p,0,1); }`;</p><p>const fs=`#version 300 es</p><p>precision highp float; in vec2 uv; out vec4 o; uniform float t;</p><p>float h(vec2 p){ return fract(sin(dot(p,vec2(127.1,311.7)))*43758.5453); }</p><p>float n(vec2 p){ vec2 i=floor(p), f=fract(p); float A=h(i),B=h(i+vec2(1,0)),C=h(i+vec2(0,1)),D=h(i+vec2(1,1));</p><p>vec2 u=f*f*(3.-2.*f); return mix(A,B,u.x)+(C-A)*u.y*(1.-u.x)+(D-B)*u.x*u.y; }</p><p>float f(vec2 p){ float v=0., s=.5; mat2 m=mat2(1.6,1.2,-1.2,1.6); for(int i=0;i&lt;5;i++){ v+=s*n(p); p=m*p; s*=.5; } return v; }</p><p>void main(){ vec2 p=(uv-.5)*vec2(1.6,1.0); float q=f(p*1.6+vec2(t*.4,-t*.3)); float d=smoothstep(.35,.95,q); vec3 c=mix(vec3(.24,.88,1.),vec3(.61,.36,1.),uv.x); o=vec4(c*d,.6*d); }`;</p><p>function sh(src,type){const s=gl.createShader(type);gl.shaderSource(s,src);gl.compileShader(s);return s;}</p><p>const prog=gl.createProgram(); gl.attachShader(prog,sh(vs,gl.VERTEX_SHADER)); gl.attachShader(prog,sh(fs,gl.FRAGMENT_SHADER)); gl.linkProgram(prog);</p><p>const ut=gl.getUniformLocation(prog,'t');</p><p>function draw(now){ gl.useProgram(prog); gl.uniform1f(ut,(now-start)*1e-3); gl.drawArrays(gl.TRIANGLES,0,3); requestAnimationFrame(draw); }</p><p>requestAnimationFrame(draw);</p><p>})();</p><p>&lt;/script&gt;</p><p>&lt;/body&gt;</p><p>&lt;/html&gt;</p><p></p>
